   1→/**
   2→ * Worktree Management Module
   3→ *
   4→ * Handles git worktree lifecycle operations for issue isolation:
   5→ * - Creation and reuse of feature worktrees
   6→ * - Staleness detection and refresh
   7→ * - Dependency installation
   8→ * - PR creation and rebase operations
   9→ *
  10→ * @module worktree-manager
  11→ */
  12→
  13→import chalk from "chalk";
  14→import { spawnSync } from "child_process";
  15→import { existsSync, readFileSync } from "fs";
  16→import path from "path";
  17→import { PM_CONFIG } from "../stacks.js";
  18→import type { CacheMetrics } from "./run-log-schema.js";
  19→
  20→/**
  21→ * Worktree information for an issue
  22→ */
  23→export interface WorktreeInfo {
  24→  issue: number;
  25→  path: string;
  26→  branch: string;
  27→  existed: boolean;
  28→  /** True if an existing branch was rebased onto the chain base */
  29→  rebased: boolean;
  30→}
  31→
  32→/**
  33→ * Result of worktree freshness check
  34→ */
  35→export interface WorktreeFreshnessResult {
  36→  /** True if worktree is stale (significantly behind main) */
  37→  isStale: boolean;
  38→  /** Number of commits behind origin/main */
  39→  commitsBehind: number;
  40→  /** True if worktree has uncommitted changes */
  41→  hasUncommittedChanges: boolean;
  42→  /** True if worktree has unpushed commits */
  43→  hasUnpushedCommits: boolean;
  44→}
  45→
  46→/**
  47→ * Result of a pre-PR rebase operation
  48→ */
  49→export interface RebaseResult {
  50→  /** Whether the rebase was performed */
  51→  performed: boolean;
  52→  /** Whether the rebase succeeded */
  53→  success: boolean;
  54→  /** Whether dependencies were reinstalled */
  55→  reinstalled: boolean;
  56→  /** Error message if rebase failed */
  57→  error?: string;
  58→}
  59→
  60→/**
  61→ * Result of PR creation
  62→ */
  63→export interface PRCreationResult {
  64→  /** Whether PR creation was attempted */
  65→  attempted: boolean;
  66→  /** Whether PR was created successfully (or already existed) */
  67→  success: boolean;
  68→  /** PR number */
  69→  prNumber?: number;
  70→  /** PR URL */
  71→  prUrl?: string;
  72→  /** Error message if failed */
  73→  error?: string;
  74→}
  75→
  76→/**
  77→ * Lockfile names for different package managers
  78→ */
  79→const LOCKFILES = [
  80→  "package-lock.json",
  81→  "pnpm-lock.yaml",
  82→  "bun.lock",
  83→  "yarn.lock",
  84→];
  85→
  86→/**
  87→ * Slugify a title for branch naming
  88→ */
  89→export function slugify(title: string): string {
  90→  return title
  91→    .toLowerCase()
  92→    .replace(/[^a-z0-9]+/g, "-")
  93→    .replace(/^-+|-+$/g, "")
  94→    .substring(0, 50);
  95→}
  96→
  97→/**
  98→ * Get the git repository root directory
  99→ */
 100→export function getGitRoot(): string | null {
 101→  const result = spawnSync("git", ["rev-parse", "--show-toplevel"], {
 102→    stdio: "pipe",
 103→  });
 104→  if (result.status === 0) {
 105→    return result.stdout.toString().trim();
 106→  }
 107→  return null;
 108→}
 109→
 110→/**
 111→ * Check if a worktree exists for a given branch
 112→ */
 113→export function findExistingWorktree(branch: string): string | null {
 114→  const result = spawnSync("git", ["worktree", "list", "--porcelain"], {
 115→    stdio: "pipe",
 116→  });
 117→  if (result.status !== 0) return null;
 118→
 119→  const output = result.stdout.toString();
 120→  const lines = output.split("\n");
 121→  let currentPath = "";
 122→
 123→  for (const line of lines) {
 124→    if (line.startsWith("worktree ")) {
 125→      currentPath = line.substring(9);
 126→    } else if (line.startsWith("branch refs/heads/") && line.includes(branch)) {
 127→      return currentPath;
 128→    }
 129→  }
 130→  return null;
 131→}
 132→
 133→/**
 134→ * Check if a worktree is stale (behind origin/main) and should be recreated
 135→ *
 136→ * @param worktreePath - Path to the worktree
 137→ * @param verbose - Enable verbose output
 138→ * @returns Freshness check result
 139→ */
 140→export function checkWorktreeFreshness(
 141→  worktreePath: string,
 142→  verbose: boolean,
 143→): WorktreeFreshnessResult {
 144→  const result: WorktreeFreshnessResult = {
 145→    isStale: false,
 146→    commitsBehind: 0,
 147→    hasUncommittedChanges: false,
 148→    hasUnpushedCommits: false,
 149→  };
 150→
 151→  // Fetch latest main to ensure accurate comparison
 152→  spawnSync("git", ["-C", worktreePath, "fetch", "origin", "main"], {
 153→    stdio: "pipe",
 154→    timeout: 30000,
 155→  });
 156→
 157→  // Check for uncommitted changes
 158→  const statusResult = spawnSync(
 159→    "git",
 160→    ["-C", worktreePath, "status", "--porcelain"],
 161→    { stdio: "pipe" },
 162→  );
 163→  if (statusResult.status === 0) {
 164→    result.hasUncommittedChanges =
 165→      statusResult.stdout.toString().trim().length > 0;
 166→  }
 167→
 168→  // Get merge base with origin/main
 169→  const mergeBaseResult = spawnSync(
 170→    "git",
 171→    ["-C", worktreePath, "merge-base", "HEAD", "origin/main"],
 172→    { stdio: "pipe" },
 173→  );
 174→  if (mergeBaseResult.status !== 0) {
 175→    // Can't determine merge base - not stale
 176→    return result;
 177→  }
 178→  const mergeBase = mergeBaseResult.stdout.toString().trim();
 179→
 180→  // Get origin/main HEAD
 181→  const mainHeadResult = spawnSync(
 182→    "git",
 183→    ["-C", worktreePath, "rev-parse", "origin/main"],
 184→    { stdio: "pipe" },
 185→  );
 186→  if (mainHeadResult.status !== 0) {
 187→    return result;
 188→  }
 189→  const mainHead = mainHeadResult.stdout.toString().trim();
 190→
 191→  // Count commits behind main
 192→  if (mergeBase !== mainHead) {
 193→    const countResult = spawnSync(
 194→      "git",
 195→      ["-C", worktreePath, "rev-list", "--count", `${mergeBase}..${mainHead}`],
 196→      { stdio: "pipe" },
 197→    );
 198→    if (countResult.status === 0) {
 199→      result.commitsBehind = parseInt(countResult.stdout.toString().trim(), 10);
 200→      // Consider stale if more than 5 commits behind (configurable threshold)
 201→      result.isStale = result.commitsBehind > 5;
 202→    }
 203→  }
 204→
 205→  // Check for unpushed commits (work in progress)
 206→  const unpushedResult = spawnSync(
 207→    "git",
 208→    ["-C", worktreePath, "log", "--oneline", "@{u}..HEAD"],
 209→    { stdio: "pipe" },
 210→  );
 211→  if (unpushedResult.status === 0) {
 212→    result.hasUnpushedCommits =
 213→      unpushedResult.stdout.toString().trim().length > 0;
 214→  }
 215→
 216→  if (verbose && result.isStale) {
 217→    console.log(
 218→      chalk.gray(
 219→        `    📊 Worktree is ${result.commitsBehind} commits behind origin/main`,
 220→      ),
 221→    );
 222→  }
 223→
 224→  return result;
 225→}
 226→
 227→/**
 228→ * Remove and recreate a stale worktree
 229→ *
 230→ * @param existingPath - Path to existing worktree
 231→ * @param branch - Branch name
 232→ * @param verbose - Enable verbose output
 233→ * @returns true if worktree was removed
 234→ */
 235→export function removeStaleWorktree(
 236→  existingPath: string,
 237→  branch: string,
 238→  verbose: boolean,
 239→): boolean {
 240→  if (verbose) {
 241→    console.log(chalk.gray(`    🗑️  Removing stale worktree...`));
 242→  }
 243→
 244→  // Remove the worktree
 245→  const removeResult = spawnSync(
 246→    "git",
 247→    ["worktree", "remove", "--force", existingPath],
 248→    { stdio: "pipe" },
 249→  );
 250→
 251→  if (removeResult.status !== 0) {
 252→    const error = removeResult.stderr.toString();
 253→    console.log(chalk.yellow(`    ⚠️  Could not remove worktree: ${error}`));
 254→    return false;
 255→  }
 256→
 257→  // Delete the branch so it can be recreated fresh
 258→  const deleteResult = spawnSync("git", ["branch", "-D", branch], {
 259→    stdio: "pipe",
 260→  });
 261→
 262→  if (deleteResult.status !== 0 && verbose) {
 263→    console.log(
 264→      chalk.gray(
 265→        `    ℹ️  Branch ${branch} not deleted (may not exist locally)`,
 266→      ),
 267→    );
 268→  }
 269→
 270→  return true;
 271→}
 272→
 273→/**
 274→ * List all active worktrees with their branches
 275→ */
 276→export function listWorktrees(): Array<{
 277→  path: string;
 278→  branch: string;
 279→  issue: number | null;
 280→}> {
 281→  const result = spawnSync("git", ["worktree", "list", "--porcelain"], {
 282→    stdio: "pipe",
 283→  });
 284→  if (result.status !== 0) return [];
 285→
 286→  const output = result.stdout.toString();
 287→  const lines = output.split("\n");
 288→  const worktrees: Array<{
 289→    path: string;
 290→    branch: string;
 291→    issue: number | null;
 292→  }> = [];
 293→
 294→  let currentPath = "";
 295→  let currentBranch = "";
 296→
 297→  for (const line of lines) {
 298→    if (line.startsWith("worktree ")) {
 299→      currentPath = line.substring(9);
 300→    } else if (line.startsWith("branch refs/heads/")) {
 301→      currentBranch = line.substring(18);
 302→      // Extract issue number from branch name (e.g., feature/123-some-title)
 303→      const issueMatch = currentBranch.match(/feature\/(\d+)-/);
 304→      const issue = issueMatch ? parseInt(issueMatch[1], 10) : null;
 305→      worktrees.push({ path: currentPath, branch: currentBranch, issue });
 306→      currentPath = "";
 307→      currentBranch = "";
 308→    }
 309→  }
 310→
 311→  return worktrees;
 312→}
 313→
 314→/**
 315→ * Get changed files in a worktree compared to main
 316→ */
 317→export function getWorktreeChangedFiles(worktreePath: string): string[] {
 318→  const result = spawnSync(
 319→    "git",
 320→    ["-C", worktreePath, "diff", "--name-only", "main...HEAD"],
 321→    { stdio: "pipe" },
 322→  );
 323→  if (result.status !== 0) return [];
 324→  return result.stdout
 325→    .toString()
 326→    .trim()
 327→    .split("\n")
 328→    .filter((f) => f.length > 0);
 329→}
 330→
 331→/**
 332→ * Get diff stats for a worktree (files changed, lines added)
 333→ * Returns aggregate metrics only - no file paths to preserve privacy
 334→ */
 335→export function getWorktreeDiffStats(worktreePath: string): {
 336→  filesChanged: number;
 337→  linesAdded: number;
 338→} {
 339→  const result = spawnSync(
 340→    "git",
 341→    ["-C", worktreePath, "diff", "--stat", "main...HEAD"],
 342→    { stdio: "pipe" },
 343→  );
 344→
 345→  if (result.status !== 0) {
 346→    return { filesChanged: 0, linesAdded: 0 };
 347→  }
 348→
 349→  const output = result.stdout.toString();
 350→  const lines = output.trim().split("\n");
 351→
 352→  // Summary line is last and looks like: " 5 files changed, 100 insertions(+), 20 deletions(-)"
 353→  const summaryLine = lines[lines.length - 1];
 354→  if (!summaryLine) {
 355→    return { filesChanged: 0, linesAdded: 0 };
 356→  }
 357→
 358→  const filesMatch = summaryLine.match(/(\d+)\s+files?\s+changed/);
 359→  const insertionsMatch = summaryLine.match(/(\d+)\s+insertions?\(\+\)/);
 360→
 361→  return {
 362→    filesChanged: filesMatch ? parseInt(filesMatch[1], 10) : 0,
 363→    linesAdded: insertionsMatch ? parseInt(insertionsMatch[1], 10) : 0,
 364→  };
 365→}
 366→
 367→/**
 368→ * Read cache metrics from QA phase (AC-7)
 369→ *
 370→ * @param worktreePath - Path to the worktree
 371→ * @returns CacheMetrics or undefined if not available
 372→ */
 373→export function readCacheMetrics(
 374→  worktreePath?: string,
 375→): CacheMetrics | undefined {
 376→  const cacheMetricsPath = worktreePath
 377→    ? path.join(worktreePath, ".sequant/.cache/qa/cache-metrics.json")
 378→    : ".sequant/.cache/qa/cache-metrics.json";
 379→
 380→  if (!existsSync(cacheMetricsPath)) {
 381→    return undefined;
 382→  }
 383→
 384→  try {
 385→    const content = readFileSync(cacheMetricsPath, "utf-8");
 386→    const data = JSON.parse(content);
 387→
 388→    if (
 389→      typeof data.hits === "number" &&
 390→      typeof data.misses === "number" &&
 391→      typeof data.skipped === "number"
 392→    ) {
 393→      return {
 394→        hits: data.hits,
 395→        misses: data.misses,
 396→        skipped: data.skipped,
 397→      };
 398→    }
 399→  } catch {
 400→    // Ignore parse errors
 401→  }
 402→
 403→  return undefined;
 404→}
 405→
 406→/**
 407→ * Create a checkpoint commit in the worktree after QA passes
 408→ * This allows recovery in case later issues in the chain fail
 409→ * @internal Exported for testing
 410→ */
 411→export function createCheckpointCommit(
 412→  worktreePath: string,
 413→  issueNumber: number,
 414→  verbose: boolean,
 415→): boolean {
 416→  // Check if there are uncommitted changes
 417→  const statusResult = spawnSync(
 418→    "git",
 419→    ["-C", worktreePath, "status", "--porcelain"],
 420→    { stdio: "pipe" },
 421→  );
 422→
 423→  if (statusResult.status !== 0) {
 424→    if (verbose) {
 425→      console.log(
 426→        chalk.yellow(`    ⚠️  Could not check git status for checkpoint`),
 427→      );
 428→    }
 429→    return false;
 430→  }
 431→
 432→  const hasChanges = statusResult.stdout.toString().trim().length > 0;
 433→  if (!hasChanges) {
 434→    if (verbose) {
 435→      console.log(
 436→        chalk.gray(`    📌 No changes to checkpoint (already committed)`),
 437→      );
 438→    }
 439→    return true;
 440→  }
 441→
 442→  // Stage all changes
 443→  const addResult = spawnSync("git", ["-C", worktreePath, "add", "-A"], {
 444→    stdio: "pipe",
 445→  });
 446→
 447→  if (addResult.status !== 0) {
 448→    if (verbose) {
 449→      console.log(
 450→        chalk.yellow(`    ⚠️  Could not stage changes for checkpoint`),
 451→      );
 452→    }
 453→    return false;
 454→  }
 455→
 456→  // Create checkpoint commit
 457→  const commitMessage = `checkpoint(#${issueNumber}): QA passed
 458→
 459→This is an automatic checkpoint commit created after issue #${issueNumber}
 460→passed QA in chain mode. It serves as a recovery point if later issues fail.`;
 461→
 462→  const commitResult = spawnSync(
 463→    "git",
 464→    ["-C", worktreePath, "commit", "-m", commitMessage],
 465→    { stdio: "pipe" },
 466→  );
 467→
 468→  if (commitResult.status !== 0) {
 469→    const error = commitResult.stderr.toString();
 470→    if (verbose) {
 471→      console.log(
 472→        chalk.yellow(`    ⚠️  Could not create checkpoint commit: ${error}`),
 473→      );
 474→    }
 475→    return false;
 476→  }
 477→
 478→  console.log(
 479→    chalk.green(`    📌 Checkpoint commit created for #${issueNumber}`),
 480→  );
 481→  return true;
 482→}
