 484→/**
 485→ * Check if any lockfile changed during a rebase and re-run install if needed.
 486→ * This prevents dependency drift when the lockfile was updated on main.
 487→ * @param worktreePath Path to the worktree
 488→ * @param packageManager Package manager to use for install
 489→ * @param verbose Whether to show verbose output
 490→ * @param preRebaseRef Git ref pointing to pre-rebase HEAD (defaults to ORIG_HEAD,
 491→ *        which git sets automatically after rebase). Using ORIG_HEAD captures all
 492→ *        lockfile changes across multi-commit rebases, unlike HEAD~1 which only
 493→ *        checks the last commit.
 494→ * @returns true if reinstall was performed, false otherwise
 495→ * @internal Exported for testing
 496→ */
 497→export function reinstallIfLockfileChanged(
 498→  worktreePath: string,
 499→  packageManager: string | undefined,
 500→  verbose: boolean,
 501→  preRebaseRef: string = "ORIG_HEAD",
 502→): boolean {
 503→  // Compare pre-rebase state to current HEAD to detect all lockfile changes
 504→  // introduced by the rebase (including changes from main that were pulled in)
 505→  let lockfileChanged = false;
 506→
 507→  for (const lockfile of LOCKFILES) {
 508→    const result = spawnSync(
 509→      "git",
 510→      [
 511→        "-C",
 512→        worktreePath,
 513→        "diff",
 514→        "--name-only",
 515→        `${preRebaseRef}..HEAD`,
 516→        "--",
 517→        lockfile,
 518→      ],
 519→      { stdio: "pipe" },
 520→    );
 521→
 522→    if (result.status === 0 && result.stdout.toString().trim().length > 0) {
 523→      lockfileChanged = true;
 524→      if (verbose) {
 525→        console.log(chalk.gray(`    📦 Lockfile changed: ${lockfile}`));
 526→      }
 527→      break;
 528→    }
 529→  }
 530→
 531→  if (!lockfileChanged) {
 532→    if (verbose) {
 533→      console.log(chalk.gray(`    📦 No lockfile changes detected`));
 534→    }
 535→    return false;
 536→  }
 537→
 538→  // Re-run install to sync node_modules with updated lockfile
 539→  console.log(
 540→    chalk.blue(`    📦 Reinstalling dependencies (lockfile changed)...`),
 541→  );
 542→
 543→  const pm = (packageManager as keyof typeof PM_CONFIG) || "npm";
 544→  const pmConfig = PM_CONFIG[pm];
 545→  const [cmd, ...args] = pmConfig.installSilent.split(" ");
 546→
 547→  const installResult = spawnSync(cmd, args, {
 548→    cwd: worktreePath,
 549→    stdio: "pipe",
 550→  });
 551→
 552→  if (installResult.status !== 0) {
 553→    const error = installResult.stderr.toString();
 554→    console.log(
 555→      chalk.yellow(`    ⚠️  Dependency reinstall failed: ${error.trim()}`),
 556→    );
 557→    return false;
 558→  }
 559→
 560→  console.log(chalk.green(`    ✅ Dependencies reinstalled`));
 561→  return true;
 562→}
 563→
 564→/**
 565→ * Rebase the worktree branch onto origin/main before PR creation.
 566→ * This ensures the branch is up-to-date and prevents lockfile drift.
 567→ *
 568→ * @param worktreePath Path to the worktree
 569→ * @param issueNumber Issue number (for logging)
 570→ * @param packageManager Package manager to use if reinstall needed
 571→ * @param verbose Whether to show verbose output
 572→ * @returns RebaseResult indicating success/failure and whether reinstall was performed
 573→ * @internal Exported for testing
 574→ */
 575→export function rebaseBeforePR(
 576→  worktreePath: string,
 577→  issueNumber: number,
 578→  packageManager: string | undefined,
 579→  verbose: boolean,
 580→): RebaseResult {
 581→  if (verbose) {
 582→    console.log(
 583→      chalk.gray(
 584→        `    🔄 Rebasing #${issueNumber} onto origin/main before PR...`,
 585→      ),
 586→    );
 587→  }
 588→
 589→  // Fetch latest main to ensure we're rebasing onto fresh state
 590→  const fetchResult = spawnSync(
 591→    "git",
 592→    ["-C", worktreePath, "fetch", "origin", "main"],
 593→    {
 594→      stdio: "pipe",
 595→    },
 596→  );
 597→
 598→  if (fetchResult.status !== 0) {
 599→    const error = fetchResult.stderr.toString();
 600→    console.log(
 601→      chalk.yellow(`    ⚠️  Could not fetch origin/main: ${error.trim()}`),
 602→    );
 603→    // Continue anyway - might work with local state
 604→  }
 605→
 606→  // Perform the rebase
 607→  const rebaseResult = spawnSync(
 608→    "git",
 609→    ["-C", worktreePath, "rebase", "origin/main"],
 610→    { stdio: "pipe" },
 611→  );
 612→
 613→  if (rebaseResult.status !== 0) {
 614→    const rebaseError = rebaseResult.stderr.toString();
 615→
 616→    // Check if it's a conflict
 617→    if (
 618→      rebaseError.includes("CONFLICT") ||
 619→      rebaseError.includes("could not apply")
 620→    ) {
 621→      console.log(
 622→        chalk.yellow(
 623→          `    ⚠️  Rebase conflict detected. Aborting rebase and keeping original branch state.`,
 624→        ),
 625→      );
 626→      console.log(
 627→        chalk.yellow(
 628→          `    ℹ️  PR will be created without rebase. Manual rebase may be required before merge.`,
 629→        ),
 630→      );
 631→
 632→      // Abort the rebase to restore branch state
 633→      spawnSync("git", ["-C", worktreePath, "rebase", "--abort"], {
 634→        stdio: "pipe",
 635→      });
 636→
 637→      return {
 638→        performed: true,
 639→        success: false,
 640→        reinstalled: false,
 641→        error: "Rebase conflict - manual resolution required",
 642→      };
 643→    } else {
 644→      console.log(chalk.yellow(`    ⚠️  Rebase failed: ${rebaseError.trim()}`));
 645→      console.log(
 646→        chalk.yellow(`    ℹ️  Continuing with branch in its original state.`),
 647→      );
 648→
 649→      return {
 650→        performed: true,
 651→        success: false,
 652→        reinstalled: false,
 653→        error: rebaseError.trim(),
 654→      };
 655→    }
 656→  }
 657→
 658→  console.log(chalk.green(`    ✅ Branch rebased onto origin/main`));
 659→
 660→  // Check if lockfile changed and reinstall if needed
 661→  const reinstalled = reinstallIfLockfileChanged(
 662→    worktreePath,
 663→    packageManager,
 664→    verbose,
 665→  );
 666→
 667→  return {
 668→    performed: true,
 669→    success: true,
 670→    reinstalled,
 671→  };
 672→}
