 674→/**
 675→ * Push branch and create a PR after successful QA.
 676→ *
 677→ * Handles both fresh PR creation and detection of existing PRs.
 678→ * Failures are warnings — they don't fail the run.
 679→ *
 680→ * @param worktreePath Path to the worktree
 681→ * @param issueNumber Issue number
 682→ * @param issueTitle Issue title (for PR title)
 683→ * @param branch Branch name
 684→ * @param verbose Whether to show verbose output
 685→ * @returns PRCreationResult with PR info or error
 686→ * @internal Exported for testing
 687→ */
 688→export function createPR(
 689→  worktreePath: string,
 690→  issueNumber: number,
 691→  issueTitle: string,
 692→  branch: string,
 693→  verbose: boolean,
 694→  labels?: string[],
 695→): PRCreationResult {
 696→  // Step 1: Check for existing PR on this branch
 697→  const existingPR = spawnSync(
 698→    "gh",
 699→    ["pr", "view", branch, "--json", "number,url"],
 700→    { stdio: "pipe", cwd: worktreePath, timeout: 15000 },
 701→  );
 702→
 703→  if (existingPR.status === 0 && existingPR.stdout) {
 704→    try {
 705→      const prInfo = JSON.parse(existingPR.stdout.toString());
 706→      if (prInfo.number && prInfo.url) {
 707→        if (verbose) {
 708→          console.log(
 709→            chalk.gray(
 710→              `    ℹ️  PR #${prInfo.number} already exists for branch ${branch}`,
 711→            ),
 712→          );
 713→        }
 714→        return {
 715→          attempted: true,
 716→          success: true,
 717→          prNumber: prInfo.number,
 718→          prUrl: prInfo.url,
 719→        };
 720→      }
 721→    } catch {
 722→      // JSON parse failed — no existing PR, continue to create
 723→    }
 724→  }
 725→
 726→  // Step 2: Push branch to remote
 727→  if (verbose) {
 728→    console.log(chalk.gray(`    🚀 Pushing branch ${branch} to origin...`));
 729→  }
 730→
 731→  const pushResult = spawnSync(
 732→    "git",
 733→    ["-C", worktreePath, "push", "-u", "origin", branch],
 734→    { stdio: "pipe", timeout: 60000 },
 735→  );
 736→
 737→  if (pushResult.status !== 0) {
 738→    const pushError = pushResult.stderr?.toString().trim() ?? "Unknown error";
 739→    console.log(chalk.yellow(`    ⚠️  git push failed: ${pushError}`));
 740→    return {
 741→      attempted: true,
 742→      success: false,
 743→      error: `git push failed: ${pushError}`,
 744→    };
 745→  }
 746→
 747→  // Step 3: Create PR
 748→  if (verbose) {
 749→    console.log(chalk.gray(`    📝 Creating PR for #${issueNumber}...`));
 750→  }
 751→
 752→  const isBug = labels?.some((l) => /^bug/i.test(l));
 753→  const prefix = isBug ? "fix" : "feat";
 754→  const prTitle = `${prefix}(#${issueNumber}): ${issueTitle}`;
 755→  const prBody = [
 756→    `## Summary`,
 757→    ``,
 758→    `Automated PR for issue #${issueNumber}.`,
 759→    ``,
 760→    `Fixes #${issueNumber}`,
 761→    ``,
 762→    `---`,
 763→    `🤖 Generated by \`sequant run\``,
 764→  ].join("\n");
 765→
 766→  const prResult = spawnSync(
 767→    "gh",
 768→    ["pr", "create", "--title", prTitle, "--body", prBody, "--head", branch],
 769→    { stdio: "pipe", cwd: worktreePath, timeout: 30000 },
 770→  );
 771→
 772→  if (prResult.status !== 0) {
 773→    const prError = prResult.stderr?.toString().trim() ?? "Unknown error";
 774→    // Check if PR already exists (race condition or push-before-PR scenarios)
 775→    if (prError.includes("already exists")) {
 776→      const retryView = spawnSync(
 777→        "gh",
 778→        ["pr", "view", branch, "--json", "number,url"],
 779→        { stdio: "pipe", cwd: worktreePath, timeout: 15000 },
 780→      );
 781→      if (retryView.status === 0 && retryView.stdout) {
 782→        try {
 783→          const prInfo = JSON.parse(retryView.stdout.toString());
 784→          return {
 785→            attempted: true,
 786→            success: true,
 787→            prNumber: prInfo.number,
 788→            prUrl: prInfo.url,
 789→          };
 790→        } catch {
 791→          // Fall through to error
 792→        }
 793→      }
 794→    }
 795→    console.log(chalk.yellow(`    ⚠️  PR creation failed: ${prError}`));
 796→    return {
 797→      attempted: true,
 798→      success: false,
 799→      error: `gh pr create failed: ${prError}`,
 800→    };
 801→  }
 802→
 803→  // Step 4: Extract PR URL from output and get PR details
 804→  const prOutput = prResult.stdout?.toString().trim() ?? "";
 805→  const prUrlMatch = prOutput.match(
 806→    /https:\/\/github\.com\/[^\s]+\/pull\/(\d+)/,
 807→  );
 808→
 809→  if (prUrlMatch) {
 810→    const prNumber = parseInt(prUrlMatch[1], 10);
 811→    const prUrl = prUrlMatch[0];
 812→    console.log(chalk.green(`    ✅ PR #${prNumber} created: ${prUrl}`));
 813→    return {
 814→      attempted: true,
 815→      success: true,
 816→      prNumber,
 817→      prUrl,
 818→    };
 819→  }
 820→
 821→  // Fallback: try gh pr view to get details
 822→  const viewResult = spawnSync(
 823→    "gh",
 824→    ["pr", "view", branch, "--json", "number,url"],
 825→    { stdio: "pipe", cwd: worktreePath, timeout: 15000 },
 826→  );
 827→
 828→  if (viewResult.status === 0 && viewResult.stdout) {
 829→    try {
 830→      const prInfo = JSON.parse(viewResult.stdout.toString());
 831→      console.log(
 832→        chalk.green(`    ✅ PR #${prInfo.number} created: ${prInfo.url}`),
 833→      );
 834→      return {
 835→        attempted: true,
 836→        success: true,
 837→        prNumber: prInfo.number,
 838→        prUrl: prInfo.url,
 839→      };
 840→    } catch {
 841→      // Fall through
 842→    }
 843→  }
 844→
 845→  // PR was created but we couldn't parse the URL
 846→  console.log(
 847→    chalk.yellow(
 848→      `    ⚠️  PR created but could not extract URL from output: ${prOutput}`,
 849→    ),
 850→  );
 851→  return {
 852→    attempted: true,
 853→    success: true,
 854→    error: "PR created but URL extraction failed",
 855→  };
 856→}
 857→
 858→/**
 859→ * Create or reuse a worktree for an issue
 860→ * @param baseBranch - Optional branch to use as base instead of origin/main (for chain mode)
 861→ * @param chainMode - If true and branch exists, rebase onto baseBranch instead of using as-is
 862→ */
 863→export async function ensureWorktree(
 864→  issueNumber: number,
 865→  title: string,
 866→  verbose: boolean,
 867→  packageManager?: string,
 868→  baseBranch?: string,
 869→  chainMode?: boolean,
 870→): Promise<WorktreeInfo | null> {
 871→  const gitRoot = getGitRoot();
 872→  if (!gitRoot) {
 873→    console.log(chalk.red("    ❌ Not in a git repository"));
 874→    return null;
 875→  }
 876→
 877→  const slug = slugify(title);
 878→  const branch = `feature/${issueNumber}-${slug}`;
 879→  const worktreesDir = path.join(path.dirname(gitRoot), "worktrees");
 880→  const worktreePath = path.join(worktreesDir, branch);
 881→
 882→  // Check if worktree already exists
 883→  let existingPath = findExistingWorktree(branch);
 884→  if (existingPath) {
 885→    // AC-3: Check if worktree is stale and needs recreation
 886→    const freshness = checkWorktreeFreshness(existingPath, verbose);
 887→
 888→    if (freshness.isStale) {
 889→      // AC-3: Handle stale worktrees - check for work in progress
 890→      if (freshness.hasUncommittedChanges) {
 891→        console.log(
 892→          chalk.yellow(
 893→            `    ⚠️  Worktree is ${freshness.commitsBehind} commits behind main but has uncommitted changes`,
 894→          ),
 895→        );
 896→        console.log(
 897→          chalk.yellow(
 898→            `    ℹ️  Keeping existing worktree. Commit or stash changes, then re-run.`,
 899→          ),
 900→        );
 901→        // Continue with existing worktree
 902→      } else if (freshness.hasUnpushedCommits) {
 903→        console.log(
 904→          chalk.yellow(
 905→            `    ⚠️  Worktree is ${freshness.commitsBehind} commits behind main but has unpushed commits`,
 906→          ),
 907→        );
 908→        console.log(
 909→          chalk.yellow(`    ℹ️  Keeping existing worktree with WIP commits.`),
 910→        );
 911→        // Continue with existing worktree
 912→      } else {
 913→        // Safe to recreate - no uncommitted/unpushed work
 914→        console.log(
 915→          chalk.yellow(
 916→            `    ⚠️  Worktree is ${freshness.commitsBehind} commits behind main — recreating fresh`,
 917→          ),
 918→        );
 919→
 920→        if (removeStaleWorktree(existingPath, branch, verbose)) {
 921→          existingPath = null; // Will fall through to create new worktree
 922→        }
 923→      }
 924→    }
 925→  }
 926→
 927→  if (existingPath) {
 928→    if (verbose) {
 929→      console.log(
 930→        chalk.gray(`    📂 Reusing existing worktree: ${existingPath}`),
 931→      );
 932→    }
 933→
 934→    // In chain mode, rebase existing worktree onto previous chain link
 935→    if (chainMode && baseBranch) {
 936→      if (verbose) {
 937→        console.log(
 938→          chalk.gray(
 939→            `    🔄 Rebasing existing worktree onto chain base (${baseBranch})...`,
 940→          ),
 941→        );
 942→      }
 943→
 944→      const rebaseResult = spawnSync(
 945→        "git",
 946→        ["-C", existingPath, "rebase", baseBranch],
 947→        { stdio: "pipe" },
 948→      );
 949→
 950→      if (rebaseResult.status !== 0) {
 951→        const rebaseError = rebaseResult.stderr.toString();
 952→
 953→        // Check if it's a conflict
 954→        if (
 955→          rebaseError.includes("CONFLICT") ||
 956→          rebaseError.includes("could not apply")
 957→        ) {
 958→          console.log(
 959→            chalk.yellow(
 960→              `    ⚠️  Rebase conflict detected. Aborting rebase and keeping original branch state.`,
 961→            ),
 962→          );
 963→          console.log(
 964→            chalk.yellow(
 965→              `    ℹ️  Branch ${branch} is not properly chained. Manual rebase may be required.`,
 966→            ),
 967→          );
 968→
 969→          // Abort the rebase to restore branch state
 970→          spawnSync("git", ["-C", existingPath, "rebase", "--abort"], {
 971→            stdio: "pipe",
 972→          });
 973→        } else {
 974→          console.log(
 975→            chalk.yellow(`    ⚠️  Rebase failed: ${rebaseError.trim()}`),
 976→          );
 977→          console.log(
 978→            chalk.yellow(
 979→              `    ℹ️  Continuing with branch in its original state.`,
 980→            ),
 981→          );
 982→        }
 983→
 984→        return {
 985→          issue: issueNumber,
 986→          path: existingPath,
 987→          branch,
 988→          existed: true,
 989→          rebased: false,
 990→        };
 991→      }
 992→
 993→      if (verbose) {
 994→        console.log(
 995→          chalk.green(`    ✅ Existing worktree rebased onto ${baseBranch}`),
 996→        );
 997→      }
 998→
 999→      return {
1000→        issue: issueNumber,
1001→        path: existingPath,
1002→        branch,
1003→        existed: true,
1004→        rebased: true,
1005→      };
1006→    }
1007→
1008→    return {
1009→      issue: issueNumber,
1010→      path: existingPath,
1011→      branch,
1012→      existed: true,
1013→      rebased: false,
1014→    };
1015→  }
1016→
1017→  // Check if branch exists (but no worktree)
1018→  const branchCheck = spawnSync(
1019→    "git",
1020→    ["show-ref", "--verify", "--quiet", `refs/heads/${branch}`],
1021→    { stdio: "pipe" },
1022→  );
1023→  const branchExists = branchCheck.status === 0;
1024→
1025→  if (verbose) {
1026→    console.log(chalk.gray(`    🌿 Creating worktree for #${issueNumber}...`));
1027→  }
1028→
1029→  // Determine the base for the new branch
1030→  // For custom base branches, use origin/<branch> if it's a remote-style reference
1031→  // For local branches (chain mode), use as-is
1032→  const isLocalBranch =
1033→    baseBranch && !baseBranch.startsWith("origin/") && baseBranch !== "main";
1034→  const baseRef = baseBranch
1035→    ? isLocalBranch
1036→      ? baseBranch
1037→      : baseBranch.startsWith("origin/")
1038→        ? baseBranch
1039→        : `origin/${baseBranch}`
1040→    : "origin/main";
1041→
1042→  // Fetch the base branch to ensure worktree starts from fresh baseline
1043→  const branchToFetch = baseBranch
1044→    ? baseBranch.replace(/^origin\//, "")
1045→    : "main";
1046→  if (!isLocalBranch) {
1047→    if (verbose) {
1048→      console.log(chalk.gray(`    🔄 Fetching latest ${branchToFetch}...`));
1049→    }
1050→    const fetchResult = spawnSync("git", ["fetch", "origin", branchToFetch], {
1051→      stdio: "pipe",
1052→    });
1053→    if (fetchResult.status !== 0 && verbose) {
1054→      console.log(
1055→        chalk.yellow(
1056→          `    ⚠️  Could not fetch origin/${branchToFetch}, using local state`,
1057→        ),
1058→      );
1059→    }
1060→  } else if (verbose) {
1061→    console.log(chalk.gray(`    🔗 Chaining from branch: ${baseBranch}`));
1062→  }
1063→
1064→  // Ensure worktrees directory exists
1065→  if (!existsSync(worktreesDir)) {
1066→    spawnSync("mkdir", ["-p", worktreesDir], { stdio: "pipe" });
1067→  }
1068→
1069→  // Create the worktree
1070→  let createResult;
1071→  let needsRebase = false;
1072→
1073→  if (branchExists) {
1074→    // Use existing branch
1075→    createResult = spawnSync("git", ["worktree", "add", worktreePath, branch], {
1076→      stdio: "pipe",
1077→    });
1078→
1079→    // In chain mode with existing branch, mark for rebase onto previous chain link
1080→    if (chainMode && baseBranch) {
1081→      needsRebase = true;
1082→    }
1083→  } else {
1084→    // Create new branch from base reference (origin/main or previous branch in chain)
1085→    createResult = spawnSync(
1086→      "git",
1087→      ["worktree", "add", worktreePath, "-b", branch, baseRef],
1088→      { stdio: "pipe" },
1089→    );
1090→  }
1091→
1092→  if (createResult.status !== 0) {
1093→    const error = createResult.stderr.toString();
1094→    console.log(chalk.red(`    ❌ Failed to create worktree: ${error}`));
1095→    return null;
1096→  }
1097→
1098→  // Rebase existing branch onto chain base if needed
1099→  let rebased = false;
1100→  if (needsRebase) {
1101→    if (verbose) {
1102→      console.log(
1103→        chalk.gray(
1104→          `    🔄 Rebasing existing branch onto previous chain link (${baseRef})...`,
1105→        ),
1106→      );
1107→    }
1108→
1109→    const rebaseResult = spawnSync(
1110→      "git",
1111→      ["-C", worktreePath, "rebase", baseRef],
1112→      {
1113→        stdio: "pipe",
1114→      },
1115→    );
1116→
1117→    if (rebaseResult.status !== 0) {
1118→      const rebaseError = rebaseResult.stderr.toString();
1119→
1120→      // Check if it's a conflict
1121→      if (
1122→        rebaseError.includes("CONFLICT") ||
1123→        rebaseError.includes("could not apply")
1124→      ) {
1125→        console.log(
1126→          chalk.yellow(
1127→            `    ⚠️  Rebase conflict detected. Aborting rebase and keeping original branch state.`,
1128→          ),
1129→        );
1130→        console.log(
1131→          chalk.yellow(
1132→            `    ℹ️  Branch ${branch} is not properly chained. Manual rebase may be required.`,
1133→          ),
1134→        );
1135→
1136→        // Abort the rebase to restore branch state
1137→        spawnSync("git", ["-C", worktreePath, "rebase", "--abort"], {
1138→          stdio: "pipe",
1139→        });
1140→      } else {
1141→        console.log(
1142→          chalk.yellow(`    ⚠️  Rebase failed: ${rebaseError.trim()}`),
1143→        );
1144→        console.log(
1145→          chalk.yellow(`    ℹ️  Continuing with branch in its original state.`),
1146→        );
1147→      }
1148→    } else {
1149→      rebased = true;
1150→      if (verbose) {
1151→        console.log(chalk.green(`    ✅ Branch rebased onto ${baseRef}`));
1152→      }
1153→    }
1154→  }
1155→
1156→  // Copy .env.local if it exists
1157→  const envLocalSrc = path.join(gitRoot, ".env.local");
1158→  const envLocalDst = path.join(worktreePath, ".env.local");
1159→  if (existsSync(envLocalSrc) && !existsSync(envLocalDst)) {
1160→    spawnSync("cp", [envLocalSrc, envLocalDst], { stdio: "pipe" });
1161→  }
1162→
1163→  // Copy .claude/settings.local.json if it exists
1164→  const claudeSettingsSrc = path.join(
1165→    gitRoot,
1166→    ".claude",
1167→    "settings.local.json",
1168→  );
1169→  const claudeSettingsDst = path.join(
1170→    worktreePath,
1171→    ".claude",
1172→    "settings.local.json",
1173→  );
1174→  if (existsSync(claudeSettingsSrc) && !existsSync(claudeSettingsDst)) {
1175→    spawnSync("mkdir", ["-p", path.join(worktreePath, ".claude")], {
1176→      stdio: "pipe",
1177→    });
1178→    spawnSync("cp", [claudeSettingsSrc, claudeSettingsDst], { stdio: "pipe" });
1179→  }
1180→
1181→  // Install dependencies if needed
1182→  const nodeModulesPath = path.join(worktreePath, "node_modules");
1183→  if (!existsSync(nodeModulesPath)) {
1184→    if (verbose) {
1185→      console.log(chalk.gray(`    📦 Installing dependencies...`));
1186→    }
1187→    // Use detected package manager or default to npm
1188→    const pm = (packageManager as keyof typeof PM_CONFIG) || "npm";
1189→    const pmConfig = PM_CONFIG[pm];
1190→    const [cmd, ...args] = pmConfig.installSilent.split(" ");
1191→    spawnSync(cmd, args, {
1192→      cwd: worktreePath,
1193→      stdio: "pipe",
1194→    });
1195→  }
1196→
1197→  if (verbose) {
1198→    console.log(chalk.green(`    ✅ Worktree ready: ${worktreePath}`));
1199→  }
1200→
1201→  return {
1202→    issue: issueNumber,
1203→    path: worktreePath,
1204→    branch,
1205→    existed: false,
1206→    rebased,
1207→  };
1208→}
1209→
1210→/**
1211→ * Ensure worktrees exist for all issues before execution
1212→ * @param baseBranch - Optional base branch for worktree creation (default: main)
1213→ */
1214→export async function ensureWorktrees(
1215→  issues: Array<{ number: number; title: string }>,
1216→  verbose: boolean,
1217→  packageManager?: string,
1218→  baseBranch?: string,
1219→): Promise<Map<number, WorktreeInfo>> {
1220→  const worktrees = new Map<number, WorktreeInfo>();
1221→
1222→  const baseDisplay = baseBranch || "main";
1223→  console.log(chalk.blue(`\n  📂 Preparing worktrees from ${baseDisplay}...`));
1224→
1225→  for (const issue of issues) {
