1252→
1253→/**
1254→ * Ensure worktrees exist for all issues in chain mode
1255→ * Each issue branches from the previous issue's branch
1256→ * @param baseBranch - Optional starting base branch for the chain (default: main)
1257→ */
1258→export async function ensureWorktreesChain(
1259→  issues: Array<{ number: number; title: string }>,
1260→  verbose: boolean,
1261→  packageManager?: string,
1262→  baseBranch?: string,
1263→): Promise<Map<number, WorktreeInfo>> {
