1269→  );
1270→
1271→  // First issue starts from the specified base branch (or main)
1272→  let previousBranch: string | undefined = baseBranch;
1273→
1274→  for (const issue of issues) {
1275→    const worktree = await ensureWorktree(
1276→      issue.number,
1277→      issue.title,
1278→      verbose,
1279→      packageManager,
1280→      previousBranch, // Chain from previous branch (or base branch for first issue)
1281→      true, // Chain mode: rebase existing branches onto previous chain link
1282→    );
1283→    if (worktree) {
1284→      worktrees.set(issue.number, worktree);
1285→      previousBranch = worktree.branch; // Next issue will branch from this
1286→    } else {
1287→      // If worktree creation fails, stop the chain
1288→      console.log(
1289→        chalk.red(
1290→          `  ❌ Chain broken: could not create worktree for #${issue.number}`,
1291→        ),
1292→      );
1293→      break;
1294→    }
1295→  }
1296→
1297→  const created = Array.from(worktrees.values()).filter(
1298→    (w) => !w.existed,
1299→  ).length;
1300→  const reused = Array.from(worktrees.values()).filter((w) => w.existed).length;
1301→  const rebased = Array.from(worktrees.values()).filter(
1302→    (w) => w.rebased,
1303→  ).length;
1304→
1305→  if (created > 0 || reused > 0) {
