1316→      .filter((i) => worktrees.has(i.number))
1317→      .map((i) => `#${i.number}`)
1318→      .join(" → ");
1319→    console.log(chalk.gray(`  Chain: ${baseDisplay} → ${chainOrder}`));
1320→  }
1321→
1322→  return worktrees;
1323→}
