 87→ * Parse environment variables for CI configuration
 88→ */
 89→export function getEnvConfig(): Partial<RunOptions> {
 90→  const config: Partial<RunOptions> = {};
 91→
 92→  if (process.env.SEQUANT_QUALITY_LOOP === "true") {
 93→    config.qualityLoop = true;
 94→  }
 95→
 96→  if (process.env.SEQUANT_MAX_ITERATIONS) {
 97→    const maxIter = parseInt(process.env.SEQUANT_MAX_ITERATIONS, 10);
 98→    if (!isNaN(maxIter)) {
 99→      config.maxIterations = maxIter;
100→    }
101→  }
102→
103→  if (process.env.SEQUANT_SMART_TESTS === "false") {
104→    config.noSmartTests = true;
105→  }
106→
107→  if (process.env.SEQUANT_TESTGEN === "true") {
108→    config.testgen = true;
109→  }
110→
111→  return config;
112→}
113→
114→/**
115→ * Execute a batch of issues
116→ */
117→export async function executeBatch(
118→  issueNumbers: number[],
119→  config: ExecutionConfig,
120→  logWriter: LogWriter | null,
121→  stateManager: StateManager | null,
122→  options: RunOptions,
123→  issueInfoMap: Map<number, { title: string; labels: string[] }>,
124→  worktreeMap: Map<number, WorktreeInfo>,
125→  shutdownManager?: ShutdownManager,
126→  packageManager?: string,
127→): Promise<IssueResult[]> {
128→  const results: IssueResult[] = [];
129→
130→  for (const issueNumber of issueNumbers) {
131→    // Check if shutdown was triggered
132→    if (shutdownManager?.shuttingDown) {
133→      break;
134→    }
135→
136→    const issueInfo = issueInfoMap.get(issueNumber) ?? {
137→      title: `Issue #${issueNumber}`,
138→      labels: [],
139→    };
140→    const worktreeInfo = worktreeMap.get(issueNumber);
141→
142→    // Start issue logging
143→    if (logWriter) {
144→      logWriter.startIssue(issueNumber, issueInfo.title, issueInfo.labels);
145→    }
146→
147→    const result = await runIssueWithLogging(
148→      issueNumber,
149→      config,
150→      logWriter,
151→      stateManager,
152→      issueInfo.title,
153→      issueInfo.labels,
154→      options,
155→      worktreeInfo?.path,
156→      worktreeInfo?.branch,
157→      shutdownManager,
158→      false, // Batch mode doesn't support chain
159→      packageManager,
160→    );
161→    results.push(result);
162→
163→    // Record PR info in log before completing issue
164→    if (logWriter && result.prNumber && result.prUrl) {
165→      logWriter.setPRInfo(result.prNumber, result.prUrl);
166→    }
167→
168→    // Complete issue logging
169→    if (logWriter) {
170→      logWriter.completeIssue();
171→    }
172→  }
173→
174→  return results;
175→}
176→
177→/**
178→ * Execute all phases for a single issue with logging and quality loop
179→ */
180→export async function runIssueWithLogging(
181→  issueNumber: number,
182→  config: ExecutionConfig,
183→  logWriter: LogWriter | null,
184→  stateManager: StateManager | null,
185→  issueTitle: string,
186→  labels: string[],
187→  options: RunOptions,
188→  worktreePath?: string,
189→  branch?: string,
190→  shutdownManager?: ShutdownManager,
191→  chainMode?: boolean,
192→  packageManager?: string,
193→  isLastInChain?: boolean,
194→): Promise<IssueResult> {
195→  const startTime = Date.now();
196→  const phaseResults: PhaseResult[] = [];
197→  let loopTriggered = false;
198→  let sessionId: string | undefined;
199→
200→  console.log(chalk.blue(`\n  Issue #${issueNumber}`));
201→  if (worktreePath) {
202→    console.log(chalk.gray(`    Worktree: ${worktreePath}`));
203→  }
204→
205→  // Initialize state tracking for this issue
206→  if (stateManager) {
207→    try {
208→      const existingState = await stateManager.getIssueState(issueNumber);
209→      if (!existingState) {
210→        await stateManager.initializeIssue(issueNumber, issueTitle, {
211→          worktree: worktreePath,
212→          branch,
213→          qualityLoop: config.qualityLoop,
214→          maxIterations: config.maxIterations,
215→        });
216→      } else {
217→        // Update worktree info if it changed
218→        if (worktreePath && branch) {
219→          await stateManager.updateWorktreeInfo(
220→            issueNumber,
221→            worktreePath,
222→            branch,
223→          );
224→        }
225→      }
226→    } catch (error) {
227→      // State tracking errors shouldn't stop execution
228→      if (config.verbose) {
229→        console.log(chalk.yellow(`    ⚠️  State tracking error: ${error}`));
230→      }
231→    }
232→  }
233→
234→  // Determine phases for this specific issue
235→  let phases: Phase[];
236→  let detectedQualityLoop = false;
237→  let specAlreadyRan = false;
238→
239→  if (options.autoDetectPhases) {
240→    // Check if labels indicate a simple bug/fix (skip spec entirely)
241→    const lowerLabels = labels.map((l) => l.toLowerCase());
242→    const isSimpleBugFix = lowerLabels.some((label) =>
243→      BUG_LABELS.some((bugLabel) => label.includes(bugLabel)),
244→    );
245→
246→    if (isSimpleBugFix) {
247→      // Simple bug fix: skip spec, go straight to exec → qa
248→      phases = ["exec", "qa"];
249→      console.log(chalk.gray(`    Bug fix detected: ${phases.join(" → ")}`));
250→    } else {
251→      // Run spec first to get recommended workflow
252→      console.log(chalk.gray(`    Running spec to determine workflow...`));
253→
254→      // Create spinner for spec phase (1 of estimated 3: spec, exec, qa)
255→      const specSpinner = new PhaseSpinner({
256→        phase: "spec",
257→        phaseIndex: 1,
258→        totalPhases: 3, // Estimate; will be refined after spec
259→        shutdownManager,
260→      });
261→      specSpinner.start();
262→
263→      // Track spec phase start in state
264→      if (stateManager) {
265→        try {
266→          await stateManager.updatePhaseStatus(
267→            issueNumber,
268→            "spec",
269→            "in_progress",
270→          );
271→        } catch {
272→          // State tracking errors shouldn't stop execution
273→        }
274→      }
275→
276→      const specStartTime = new Date();
277→      // Note: spec runs in main repo (not worktree) for planning
278→      const specResult = await executePhaseWithRetry(
279→        issueNumber,
280→        "spec",
281→        config,
282→        sessionId,
283→        worktreePath, // Will be ignored for spec (non-isolated phase)
284→        shutdownManager,
285→        specSpinner,
286→      );
287→      const specEndTime = new Date();
288→
289→      if (specResult.sessionId) {
290→        sessionId = specResult.sessionId;
291→        // Update session ID in state for resume capability
292→        if (stateManager) {
293→          try {
294→            await stateManager.updateSessionId(
295→              issueNumber,
296→              specResult.sessionId,
297→            );
298→          } catch {
299→            // State tracking errors shouldn't stop execution
300→          }
301→        }
302→      }
303→
304→      phaseResults.push(specResult);
305→      specAlreadyRan = true;
306→
307→      // Log spec phase result
308→      // Note: Spec runs in main repo, not worktree, so no git diff stats
309→      if (logWriter) {
310→        const phaseLog = createPhaseLogFromTiming(
311→          "spec",
312→          issueNumber,
313→          specStartTime,
314→          specEndTime,
315→          specResult.success
316→            ? "success"
317→            : specResult.error?.includes("Timeout")
318→              ? "timeout"
319→              : "failure",
320→          { error: specResult.error },
321→        );
322→        logWriter.logPhase(phaseLog);
323→      }
324→
325→      // Track spec phase completion in state
326→      if (stateManager) {
327→        try {
328→          const phaseStatus = specResult.success ? "completed" : "failed";
329→          await stateManager.updatePhaseStatus(
330→            issueNumber,
331→            "spec",
332→            phaseStatus,
333→            {
334→              error: specResult.error,
335→            },
336→          );
337→        } catch {
338→          // State tracking errors shouldn't stop execution
339→        }
340→      }
341→
342→      if (!specResult.success) {
343→        specSpinner.fail(specResult.error);
344→        const durationSeconds = (Date.now() - startTime) / 1000;
345→        return {
346→          issueNumber,
347→          success: false,
348→          phaseResults,
349→          durationSeconds,
350→          loopTriggered: false,
351→        };
352→      }
353→
354→      specSpinner.succeed();
355→
356→      // Parse recommended workflow from spec output
357→      const parsedWorkflow = specResult.output
358→        ? parseRecommendedWorkflow(specResult.output)
359→        : null;
360→
361→      if (parsedWorkflow) {
362→        // Remove spec from phases since we already ran it
363→        phases = parsedWorkflow.phases.filter((p) => p !== "spec");
364→        detectedQualityLoop = parsedWorkflow.qualityLoop;
365→        console.log(
366→          chalk.gray(
367→            `    Spec recommends: ${phases.join(" → ")}${detectedQualityLoop ? " (quality loop)" : ""}`,
368→          ),
369→        );
370→      } else {
371→        // Fall back to label-based detection
372→        console.log(
373→          chalk.yellow(
374→            `    Could not parse spec recommendation, using label-based detection`,
375→          ),
376→        );
377→        const detected = detectPhasesFromLabels(labels);
378→        phases = detected.phases.filter((p) => p !== "spec");
379→        detectedQualityLoop = detected.qualityLoop;
380→        console.log(chalk.gray(`    Fallback: ${phases.join(" → ")}`));
381→      }
382→    }
383→  } else {
384→    // Use explicit phases with adjustments
385→    phases = determinePhasesForIssue(config.phases, labels, options);
386→    if (phases.length !== config.phases.length) {
387→      console.log(chalk.gray(`    Phases adjusted: ${phases.join(" → ")}`));
388→    }
389→  }
390→
391→  // Resume: filter out completed phases if --resume flag is set
392→  if (options.resume) {
393→    const resumeResult = filterResumedPhases(issueNumber, phases, true);
394→    if (resumeResult.skipped.length > 0) {
395→      console.log(
396→        chalk.gray(
397→          `    Resume: skipping completed phases: ${resumeResult.skipped.join(", ")}`,
398→        ),
399→      );
400→      phases = resumeResult.phases;
401→    }
402→    // Also skip spec if it was auto-detected as completed
403→    if (
404→      specAlreadyRan &&
405→      resumeResult.skipped.length === 0 &&
406→      resumeResult.phases.length === 0
407→    ) {
408→      console.log(chalk.gray(`    Resume: all phases already completed`));
409→    }
410→  }
411→
412→  // Add testgen phase if requested (and spec was in the phases)
413→  if (
414→    options.testgen &&
415→    (phases.includes("spec") || specAlreadyRan) &&
416→    !phases.includes("testgen")
417→  ) {
418→    // Insert testgen at the beginning if spec already ran, otherwise after spec
419→    if (specAlreadyRan) {
420→      phases.unshift("testgen");
421→    } else {
422→      const specIndex = phases.indexOf("spec");
423→      if (specIndex !== -1) {
424→        phases.splice(specIndex + 1, 0, "testgen");
425→      }
426→    }
427→  }
428→
429→  let iteration = 0;
430→  const useQualityLoop = config.qualityLoop || detectedQualityLoop;
431→  const maxIterations = useQualityLoop ? config.maxIterations : 1;
432→  let completedSuccessfully = false;
433→
434→  while (iteration < maxIterations) {
435→    iteration++;
436→
437→    if (useQualityLoop && iteration > 1) {
438→      console.log(
439→        chalk.yellow(
440→          `    Quality loop iteration ${iteration}/${maxIterations}`,
441→        ),
442→      );
443→      loopTriggered = true;
444→    }
445→
446→    let phasesFailed = false;
447→
448→    // Calculate total phases for progress indicator
449→    // If spec already ran in auto-detect mode, it's counted separately
450→    const totalPhases = specAlreadyRan ? phases.length + 1 : phases.length;
451→    const phaseIndexOffset = specAlreadyRan ? 1 : 0;
452→
453→    for (let phaseIdx = 0; phaseIdx < phases.length; phaseIdx++) {
454→      const phase = phases[phaseIdx];
455→      const phaseNumber = phaseIdx + 1 + phaseIndexOffset;
456→
457→      // Create spinner for this phase
458→      const spinner = new PhaseSpinner({
459→        phase,
460→        phaseIndex: phaseNumber,
461→        totalPhases,
462→        shutdownManager,
463→      });
464→      spinner.start();
465→
466→      // Track phase start in state
467→      if (stateManager) {
468→        try {
469→          await stateManager.updatePhaseStatus(
470→            issueNumber,
471→            phase,
472→            "in_progress",
473→          );
474→        } catch {
475→          // State tracking errors shouldn't stop execution
476→        }
477→      }
478→
479→      const phaseStartTime = new Date();
480→      const result = await executePhaseWithRetry(
481→        issueNumber,
482→        phase,
483→        config,
484→        sessionId,
485→        worktreePath,
486→        shutdownManager,
487→        spinner,
488→      );
489→      const phaseEndTime = new Date();
490→
491→      // Update session ID if we got one
492→      if (result.sessionId) {
493→        sessionId = result.sessionId;
494→        // Update session ID in state for resume capability
495→        if (stateManager) {
496→          try {
497→            await stateManager.updateSessionId(issueNumber, result.sessionId);
498→          } catch {
499→            // State tracking errors shouldn't stop execution
500→          }
501→        }
502→      }
503→
504→      // Log phase result with observability data (AC-1, AC-2, AC-3, AC-7)
505→      if (logWriter) {
506→        // Capture git diff stats for worktree phases (AC-1, AC-3)
507→        const gitDiffStats = worktreePath
508→          ? getGitDiffStats(worktreePath)
509→          : undefined;
510→
511→        // Capture commit hash after phase (AC-2)
512→        const commitHash = worktreePath
513→          ? getCommitHash(worktreePath)
514→          : undefined;
515→
516→        // Read cache metrics for QA phase (AC-7)
517→        const cacheMetrics =
518→          phase === "qa" ? readCacheMetrics(worktreePath) : undefined;
519→
520→        const phaseLog = createPhaseLogFromTiming(
521→          phase,
522→          issueNumber,
523→          phaseStartTime,
524→          phaseEndTime,
525→          result.success
526→            ? "success"
527→            : result.error?.includes("Timeout")
528→              ? "timeout"
529→              : "failure",
530→          {
531→            error: result.error,
532→            verdict: result.verdict,
533→            // Observability fields (AC-1, AC-2, AC-3, AC-7)
534→            filesModified: gitDiffStats?.filesModified,
535→            fileDiffStats: gitDiffStats?.fileDiffStats,
536→            commitHash,
537→            cacheMetrics,
538→          },
539→        );
540→        logWriter.logPhase(phaseLog);
541→      }
542→
543→      // Track phase completion in state
544→      if (stateManager) {
545→        try {
546→          const phaseStatus = result.success ? "completed" : "failed";
547→          await stateManager.updatePhaseStatus(
548→            issueNumber,
549→            phase,
550→            phaseStatus,
551→            {
552→              error: result.error,
553→            },
554→          );
555→        } catch {
556→          // State tracking errors shouldn't stop execution
557→        }
558→      }
559→
560→      phaseResults.push(result);
561→
562→      if (!result.success) {
563→        spinner.fail(result.error);
564→        phasesFailed = true;
565→        break;
566→      }
567→
568→      spinner.succeed();
569→    }
570→
571→    if (!phasesFailed) {
572→      // Check if QA passed
573→      const qaResult = phaseResults.find((r) => r.phase === "qa");
574→      if (qaResult?.success) {
575→        completedSuccessfully = true;
576→        break; // Exit quality loop on success
577→      }
578→
579→      // QA didn't pass but phases completed - might need another iteration
580→      if (useQualityLoop && iteration < maxIterations) {
581→        // Run loop phase to analyze failures and prepare for next iteration
582→        console.log(
583→          chalk.yellow(`    QA not passed, running loop analysis...`),
584→        );
585→
586→        const loopSpinner = new PhaseSpinner({
587→          phase: "loop",
588→          phaseIndex: totalPhases + 1,
589→          totalPhases: totalPhases + 1,
590→          shutdownManager,
591→        });
592→        loopSpinner.start();
593→
594→        const loopResult = await executePhaseWithRetry(
595→          issueNumber,
596→          "loop",
597→          config,
598→          sessionId,
599→          worktreePath,
600→          shutdownManager,
601→          loopSpinner,
602→        );
603→
604→        if (loopResult.sessionId) {
605→          sessionId = loopResult.sessionId;
606→        }
607→
608→        phaseResults.push(loopResult);
609→
610→        if (!loopResult.success) {
611→          loopSpinner.fail(loopResult.error);
612→          break;
613→        }
614→
615→        loopSpinner.succeed();
616→        loopTriggered = true;
617→      }
618→    } else {
619→      // Phases failed - exit loop
620→      break;
621→    }
622→  }
623→
624→  const durationSeconds = (Date.now() - startTime) / 1000;
625→
626→  // Calculate final result
627→  const qaResult = phaseResults.find((r) => r.phase === "qa");
628→  const qaPassedCleanly =
629→    qaResult?.success &&
630→    (qaResult.verdict === "READY_FOR_MERGE" ||
631→      qaResult.verdict === "NEEDS_VERIFICATION");
632→
633→  // Handle post-QA operations in chain mode or when QA passes
634→  let prNumber: number | undefined;
635→  let prUrl: string | undefined;
636→
637→  if (qaPassedCleanly && worktreePath && branch) {
638→    // Chain mode: create checkpoint commit for recovery
639→    if (chainMode) {
640→      createCheckpointCommit(worktreePath, issueNumber, config.verbose);
641→    }
642→
643→    // Rebase before PR (unless disabled)
644→    // AC-1: Non-chain mode rebases onto origin/main before PR
645→    // AC-2: Chain mode rebases only the final branch onto origin/main before PR
646→    //        (intermediate branches must stay based on their predecessor)
647→    const shouldRebase = !options.noRebase && (!chainMode || isLastInChain);
648→    if (shouldRebase) {
649→      const rebaseResult = rebaseBeforePR(
650→        worktreePath,
651→        issueNumber,
652→        packageManager,
653→        config.verbose,
654→      );
655→
656→      if (!rebaseResult.success && config.verbose) {
657→        console.log(
658→          chalk.yellow(`    ⚠️  Rebase issue: ${rebaseResult.error}`),
659→        );
660→      }
661→    }
662→
663→    // Create PR (unless disabled)
664→    if (!options.noPr) {
665→      const prResult = createPR(
666→        worktreePath,
667→        issueNumber,
668→        issueTitle,
669→        branch,
670→        config.verbose,
671→        labels,
672→      );
673→
674→      if (prResult.success) {
675→        prNumber = prResult.prNumber;
676→        prUrl = prResult.prUrl;
677→      } else if (config.verbose && prResult.error) {
678→        console.log(chalk.yellow(`    ⚠️  PR creation: ${prResult.error}`));
679→      }
680→    }
681→  }
682→
683→  // Display summary
684→  const statusIcon = completedSuccessfully ? chalk.green("✓") : chalk.red("✗");
685→  const duration = formatDuration(durationSeconds);
686→  const loopInfo = loopTriggered
687→    ? chalk.yellow(` [${iteration} iterations]`)
688→    : "";
689→
690→  console.log(
691→    chalk.blue(
692→      `\n  ${statusIcon} Issue #${issueNumber} completed in ${duration}${loopInfo}`,
693→    ),
694→  );
695→
696→  return {
697→    issueNumber,
698→    success: completedSuccessfully,
699→    phaseResults,
700→    loopTriggered,
701→    durationSeconds,
702→    prNumber,
703→    prUrl,
704→  };
705→}
