276→    );
277→    console.log(
278→      chalk.gray(
279→        "   Usage: npx sequant run 1 2 3 --sequential --chain --qa-gate",
280→      ),
281→    );
282→    return;
283→  }
284→
285→  // Sort issues by dependencies (if more than one issue)
286→  if (issueNumbers.length > 1 && !batches) {
287→    const originalOrder = [...issueNumbers];
288→    issueNumbers = sortByDependencies(issueNumbers);
289→    const orderChanged = !originalOrder.every((n, i) => n === issueNumbers[i]);
290→    if (orderChanged) {
291→      console.log(
292→        chalk.gray(
293→          `  Dependency order: ${issueNumbers.map((n) => `#${n}`).join(" → ")}`,
294→        ),
295→      );
296→    }
297→  }
298→
299→  // Build config
300→  // Note: config.phases is only used when --phases is explicitly set or autoDetect fails
301→  const explicitPhases = mergedOptions.phases
302→    ? (mergedOptions.phases.split(",").map((p) => p.trim()) as Phase[])
303→    : null;
304→
305→  // Determine MCP enablement: CLI flag (--no-mcp) → settings.run.mcp → default (true)
306→  const mcpEnabled = mergedOptions.noMcp
307→    ? false
308→    : (settings.run.mcp ?? DEFAULT_CONFIG.mcp);
309→
310→  // Resolve retry setting: CLI flag → settings.run.retry → default (true)
311→  const retryEnabled = mergedOptions.noRetry
312→    ? false
313→    : (settings.run.retry ?? true);
314→
315→  const config: ExecutionConfig = {
316→    ...DEFAULT_CONFIG,
317→    phases: explicitPhases ?? DEFAULT_PHASES,
318→    sequential: mergedOptions.sequential ?? false,
319→    dryRun: mergedOptions.dryRun ?? false,
320→    verbose: mergedOptions.verbose ?? false,
321→    phaseTimeout: mergedOptions.timeout ?? DEFAULT_CONFIG.phaseTimeout,
322→    qualityLoop: mergedOptions.qualityLoop ?? false,
323→    maxIterations: mergedOptions.maxIterations ?? DEFAULT_CONFIG.maxIterations,
324→    noSmartTests: mergedOptions.noSmartTests ?? false,
325→    mcp: mcpEnabled,
326→    retry: retryEnabled,
327→  };
328→
329→  // Propagate verbose mode to UI config so spinners use text-only mode.
330→  // This prevents animated spinner control characters from colliding with
331→  // verbose console.log() calls from StateManager/MetricsWriter (#282).
332→  if (config.verbose) {
333→    ui.configure({ verbose: true });
334→  }
335→
336→  // Initialize log writer if JSON logging enabled
337→  // Default: enabled via settings (logJson: true), can be disabled with --no-log
338→  let logWriter: LogWriter | null = null;
339→  const shouldLog =
340→    !mergedOptions.noLog &&
341→    !config.dryRun &&
342→    (mergedOptions.logJson ?? settings.run.logJson);
343→
344→  if (shouldLog) {
345→    const runConfig: RunConfig = {
346→      phases: config.phases,
347→      sequential: config.sequential,
348→      qualityLoop: config.qualityLoop,
349→      maxIterations: config.maxIterations,
350→      chain: mergedOptions.chain,
351→      qaGate: mergedOptions.qaGate,
352→    };
353→
354→    try {
355→      logWriter = new LogWriter({
356→        logPath: mergedOptions.logPath ?? settings.run.logPath,
357→        verbose: config.verbose,
358→        startCommit: getCommitHash(process.cwd()),
359→      });
360→      await logWriter.initialize(runConfig);
361→    } catch (err) {
362→      // Log initialization failure is non-fatal - warn and continue without logging
363→      // Common causes: permissions issues, disk full, invalid path
364→      const errorMessage = err instanceof Error ? err.message : String(err);
365→      console.log(
366→        chalk.yellow(
367→          `  ⚠️ Log initialization failed, continuing without logging: ${errorMessage}`,
368→        ),
369→      );
370→      logWriter = null;
371→    }
372→  }
373→
374→  // Initialize state manager for persistent workflow state tracking
375→  // State tracking is always enabled (unless dry run)
376→  let stateManager: StateManager | null = null;
377→  if (!config.dryRun) {
378→    stateManager = new StateManager({ verbose: config.verbose });
379→  }
380→
381→  // Initialize shutdown manager for graceful interruption handling
382→  const shutdown = new ShutdownManager();
383→
384→  // Register log writer finalization as cleanup task
385→  if (logWriter) {
386→    const writer = logWriter; // Capture for closure
387→    shutdown.registerCleanup("Finalize run logs", async () => {
388→      await writer.finalize();
389→    });
390→  }
391→
392→  // Display configuration
393→  console.log(chalk.gray(`  Stack: ${manifest.stack}`));
394→  if (autoDetectPhases) {
395→    console.log(chalk.gray(`  Phases: auto-detect from labels`));
396→  } else {
397→    console.log(chalk.gray(`  Phases: ${config.phases.join(" → ")}`));
398→  }
399→  console.log(
400→    chalk.gray(`  Mode: ${config.sequential ? "sequential" : "parallel"}`),
401→  );
402→  if (config.qualityLoop) {
403→    console.log(
404→      chalk.gray(
405→        `  Quality loop: enabled (max ${config.maxIterations} iterations)`,
406→      ),
407→    );
408→  }
409→  if (mergedOptions.testgen) {
410→    console.log(chalk.gray(`  Testgen: enabled`));
411→  }
412→  if (config.noSmartTests) {
413→    console.log(chalk.gray(`  Smart tests: disabled`));
414→  }
415→  if (config.dryRun) {
416→    console.log(chalk.yellow(`  ⚠️  DRY RUN - no actual execution`));
417→  }
418→  if (logWriter) {
419→    console.log(
420→      chalk.gray(
421→        `  Logging: JSON (run ${logWriter.getRunId()?.slice(0, 8)}...)`,
422→      ),
423→    );
424→  }
425→  if (stateManager) {
426→    console.log(chalk.gray(`  State tracking: enabled`));
427→  }
428→  if (mergedOptions.force) {
429→    console.log(chalk.yellow(`  Force mode: enabled (bypass state guard)`));
430→  }
431→  console.log(
432→    chalk.gray(`  Issues: ${issueNumbers.map((n) => `#${n}`).join(", ")}`),
433→  );
434→
435→  // ============================================================================
436→  // Pre-flight State Guard (#305)
437→  // ============================================================================
438→
439→  // AC-5: Auto-cleanup at run start - reconcile stale ready_for_merge states
440→  if (stateManager && !config.dryRun) {
441→    try {
442→      const reconcileResult = await reconcileStateAtStartup({
443→        verbose: config.verbose,
444→      });
445→
446→      if (reconcileResult.success && reconcileResult.advanced.length > 0) {
447→        console.log(
448→          chalk.gray(
449→            `  State reconciled: ${reconcileResult.advanced.map((n) => `#${n}`).join(", ")} → merged`,
450→          ),
451→        );
452→      }
453→    } catch {
454→      // AC-8: Graceful degradation - don't block execution on reconciliation failure
455→      if (config.verbose) {
456→        console.log(
457→          chalk.yellow(`  ⚠️  State reconciliation failed, continuing...`),
458→        );
459→      }
460→    }
461→  }
462→
463→  // AC-1 & AC-2: Pre-flight state guard - skip completed issues unless --force
464→  if (stateManager && !config.dryRun && !mergedOptions.force) {
465→    const skippedIssues: number[] = [];
466→    const activeIssues: number[] = [];
467→
468→    for (const issueNumber of issueNumbers) {
469→      try {
470→        const issueState = await stateManager.getIssueState(issueNumber);
471→        if (
472→          issueState &&
473→          (issueState.status === "ready_for_merge" ||
474→            issueState.status === "merged")
475→        ) {
476→          skippedIssues.push(issueNumber);
477→          console.log(
478→            chalk.yellow(
479→              `  ⚠️  #${issueNumber}: already ${issueState.status} — skipping (use --force to re-run)`,
480→            ),
481→          );
482→        } else {
483→          activeIssues.push(issueNumber);
484→        }
485→      } catch {
486→        // AC-8: Graceful degradation - if state check fails, include the issue
487→        activeIssues.push(issueNumber);
488→      }
489→    }
490→
491→    // Update issueNumbers to only include active issues
492→    if (skippedIssues.length > 0) {
493→      issueNumbers = activeIssues;
494→
495→      if (issueNumbers.length === 0) {
496→        console.log(
497→          chalk.yellow(
498→            `\n  All issues already completed. Use --force to re-run.`,
499→          ),
500→        );
501→        return;
502→      }
503→
504→      console.log(
505→        chalk.gray(
506→          `  Active issues: ${issueNumbers.map((n) => `#${n}`).join(", ")}`,
507→        ),
508→      );
509→    }
510→  }
511→
512→  // Worktree isolation is enabled by default for multi-issue runs
513→  const useWorktreeIsolation =
514→    mergedOptions.worktreeIsolation !== false && issueNumbers.length > 0;
515→
516→  if (useWorktreeIsolation) {
517→    console.log(chalk.gray(`  Worktree isolation: enabled`));
518→  }
519→  if (resolvedBaseBranch) {
520→    console.log(chalk.gray(`  Base branch: ${resolvedBaseBranch}`));
521→  }
522→  if (mergedOptions.chain) {
523→    console.log(
524→      chalk.gray(`  Chain mode: enabled (each issue branches from previous)`),
525→    );
526→  }
527→  if (mergedOptions.qaGate) {
528→    console.log(chalk.gray(`  QA gate: enabled (chain waits for QA pass)`));
529→  }
530→
531→  // Fetch issue info for all issues first
532→  const issueInfoMap = new Map<number, { title: string; labels: string[] }>();
533→  for (const issueNumber of issueNumbers) {
534→    issueInfoMap.set(issueNumber, await getIssueInfo(issueNumber));
535→  }
536→
537→  // Create worktrees for all issues before execution (if isolation enabled)
538→  let worktreeMap: Map<number, WorktreeInfo> = new Map();
539→  if (useWorktreeIsolation && !config.dryRun) {
540→    const issueData = issueNumbers.map((num) => ({
541→      number: num,
542→      title: issueInfoMap.get(num)?.title || `Issue #${num}`,
543→    }));
544→
545→    // Use chain mode or standard worktree creation
546→    if (mergedOptions.chain) {
547→      worktreeMap = await ensureWorktreesChain(
548→        issueData,
549→        config.verbose,
550→        manifest.packageManager,
551→        resolvedBaseBranch,
552→      );
553→    } else {
554→      worktreeMap = await ensureWorktrees(
555→        issueData,
556→        config.verbose,
557→        manifest.packageManager,
558→        resolvedBaseBranch,
559→      );
560→    }
561→
562→    // Register cleanup tasks for newly created worktrees (not pre-existing ones)
563→    for (const [issueNum, worktree] of worktreeMap.entries()) {
564→      if (!worktree.existed) {
565→        shutdown.registerCleanup(
566→          `Cleanup worktree for #${issueNum}`,
567→          async () => {
568→            // Remove worktree (leaves branch intact for recovery)
569→            const result = spawnSync(
570→              "git",
571→              ["worktree", "remove", "--force", worktree.path],
572→              {
573→                stdio: "pipe",
574→              },
575→            );
576→            if (result.status !== 0 && config.verbose) {
577→              console.log(
578→                chalk.yellow(
579→                  `    Warning: Could not remove worktree ${worktree.path}`,
580→                ),
581→              );
582→            }
583→          },
584→        );
585→      }
586→    }
587→  }
588→
589→  // Execute with graceful shutdown handling
590→  const results: IssueResult[] = [];
591→  let exitCode = 0;
592→
593→  try {
594→    if (batches) {
595→      // Batch execution: run batches sequentially, issues within batch based on mode
596→      for (let batchIdx = 0; batchIdx < batches.length; batchIdx++) {
597→        const batch = batches[batchIdx];
598→        console.log(
599→          chalk.blue(
600→            `\n  Batch ${batchIdx + 1}/${batches.length}: Issues ${batch.map((n) => `#${n}`).join(", ")}`,
601→          ),
602→        );
603→
604→        const batchResults = await executeBatch(
605→          batch,
606→          config,
607→          logWriter,
608→          stateManager,
609→          mergedOptions,
610→          issueInfoMap,
611→          worktreeMap,
612→          shutdown,
613→          manifest.packageManager,
614→        );
615→        results.push(...batchResults);
616→
617→        // Check if batch failed and we should stop
618→        const batchFailed = batchResults.some((r) => !r.success);
619→        if (batchFailed && config.sequential) {
620→          console.log(
621→            chalk.yellow(
622→              `\n  ⚠️  Batch ${batchIdx + 1} failed, stopping batch execution`,
623→            ),
624→          );
625→          break;
626→        }
627→      }
628→    } else if (config.sequential) {
629→      // Sequential execution
630→      for (let i = 0; i < issueNumbers.length; i++) {
631→        const issueNumber = issueNumbers[i];
632→        const issueInfo = issueInfoMap.get(issueNumber) ?? {
633→          title: `Issue #${issueNumber}`,
634→          labels: [],
635→        };
636→        const worktreeInfo = worktreeMap.get(issueNumber);
637→
638→        // Start issue logging
639→        if (logWriter) {
640→          logWriter.startIssue(issueNumber, issueInfo.title, issueInfo.labels);
641→        }
642→
643→        const result = await runIssueWithLogging(
644→          issueNumber,
645→          config,
646→          logWriter,
647→          stateManager,
648→          issueInfo.title,
649→          issueInfo.labels,
650→          mergedOptions,
651→          worktreeInfo?.path,
652→          worktreeInfo?.branch,
653→          shutdown,
654→          mergedOptions.chain, // Enable checkpoint commits in chain mode
655→          manifest.packageManager,
656→          // In chain mode, only the last issue should trigger pre-PR rebase
657→          mergedOptions.chain ? i === issueNumbers.length - 1 : undefined,
658→        );
659→        results.push(result);
660→
661→        // Record PR info in log before completing issue
662→        if (logWriter && result.prNumber && result.prUrl) {
663→          logWriter.setPRInfo(result.prNumber, result.prUrl);
664→        }
665→
666→        // Complete issue logging
667→        if (logWriter) {
668→          logWriter.completeIssue();
669→        }
670→
671→        // Check if shutdown was triggered
672→        if (shutdown.shuttingDown) {
673→          break;
674→        }
675→
676→        if (!result.success) {
677→          // Check if QA gate is enabled and QA specifically failed
678→          if (mergedOptions.qaGate) {
679→            const qaResult = result.phaseResults.find((p) => p.phase === "qa");
680→            const qaFailed = qaResult && !qaResult.success;
681→
682→            if (qaFailed) {
683→              // QA gate: pause chain with clear messaging
684→              console.log(chalk.yellow("\n  ⏸️  QA Gate"));
685→              console.log(
686→                chalk.yellow(
687→                  `     Issue #${issueNumber} QA did not pass. Chain paused.`,
688→                ),
689→              );
690→              console.log(
691→                chalk.gray(
692→                  "     Fix QA issues and re-run, or run /loop to auto-fix.",
693→                ),
694→              );
695→
696→              // Update state to waiting_for_qa_gate
697→              if (stateManager) {
698→                try {
699→                  await stateManager.updateIssueStatus(
700→                    issueNumber,
701→                    "waiting_for_qa_gate",
702→                  );
703→                } catch {
704→                  // State tracking errors shouldn't stop execution
705→                }
706→              }
707→              break;
708→            }
709→          }
710→
711→          const chainInfo = mergedOptions.chain ? " (chain stopped)" : "";
712→          console.log(
713→            chalk.yellow(
714→              `\n  ⚠️  Issue #${issueNumber} failed, stopping sequential execution${chainInfo}`,
715→            ),
716→          );
717→          break;
718→        }
719→      }
720→    } else {
721→      // Parallel execution (for now, just run sequentially but don't stop on failure)
722→      // TODO: Add proper parallel execution with listr2
723→      for (const issueNumber of issueNumbers) {
724→        // Check if shutdown was triggered
725→        if (shutdown.shuttingDown) {
726→          break;
727→        }
728→
729→        const issueInfo = issueInfoMap.get(issueNumber) ?? {
730→          title: `Issue #${issueNumber}`,
731→          labels: [],
732→        };
733→        const worktreeInfo = worktreeMap.get(issueNumber);
734→
735→        // Start issue logging
736→        if (logWriter) {
737→          logWriter.startIssue(issueNumber, issueInfo.title, issueInfo.labels);
738→        }
739→
740→        const result = await runIssueWithLogging(
741→          issueNumber,
742→          config,
743→          logWriter,
744→          stateManager,
745→          issueInfo.title,
746→          issueInfo.labels,
747→          mergedOptions,
748→          worktreeInfo?.path,
749→          worktreeInfo?.branch,
750→          shutdown,
751→          false, // Parallel mode doesn't support chain
752→          manifest.packageManager,
753→        );
754→        results.push(result);
755→
756→        // Record PR info in log before completing issue
757→        if (logWriter && result.prNumber && result.prUrl) {
758→          logWriter.setPRInfo(result.prNumber, result.prUrl);
759→        }
760→
761→        // Complete issue logging
762→        if (logWriter) {
763→          logWriter.completeIssue();
764→        }
765→      }
766→    }
767→
768→    // Finalize log
769→    let logPath: string | null = null;
770→    if (logWriter) {
771→      logPath = await logWriter.finalize({
772→        endCommit: getCommitHash(process.cwd()),
773→      });
774→    }
775→
776→    // Calculate success/failure counts
777→    const passed = results.filter((r) => r.success).length;
778→    const failed = results.filter((r) => !r.success).length;
779→
780→    // Record metrics (local analytics)
781→    if (!config.dryRun && results.length > 0) {
782→      try {
783→        const metricsWriter = new MetricsWriter({ verbose: config.verbose });
784→
785→        // Calculate total duration
786→        const totalDuration = results.reduce(
787→          (sum, r) => sum + (r.durationSeconds ?? 0),
788→          0,
789→        );
790→
791→        // Get unique phases from all results
792→        const allPhases = new Set<MetricPhase>();
793→        for (const result of results) {
794→          for (const phaseResult of result.phaseResults) {
795→            // Only include phases that are valid MetricPhases
796→            const phase = phaseResult.phase as MetricPhase;
797→            if (
798→              [
799→                "spec",
800→                "security-review",
801→                "testgen",
802→                "exec",
803→                "test",
804→                "qa",
805→                "loop",
806→              ].includes(phase)
807→            ) {
808→              allPhases.add(phase);
809→            }
810→          }
811→        }
812→
813→        // Calculate aggregate metrics from worktrees
814→        let totalFilesChanged = 0;
815→        let totalLinesAdded = 0;
816→        let totalQaIterations = 0;
817→
818→        for (const result of results) {
819→          const worktreeInfo = worktreeMap.get(result.issueNumber);
820→          if (worktreeInfo?.path) {
821→            const stats = getWorktreeDiffStats(worktreeInfo.path);
822→            totalFilesChanged += stats.filesChanged;
823→            totalLinesAdded += stats.linesAdded;
824→          }
825→          // Count QA iterations (loop phases indicate retries)
826→          if (result.loopTriggered) {
827→            totalQaIterations += result.phaseResults.filter(
828→              (p) => p.phase === "loop",
829→            ).length;
830→          }
831→        }
832→
833→        // Build CLI flags for metrics
834→        const cliFlags: string[] = [];
835→        if (mergedOptions.sequential) cliFlags.push("--sequential");
836→        if (mergedOptions.chain) cliFlags.push("--chain");
837→        if (mergedOptions.qaGate) cliFlags.push("--qa-gate");
838→        if (mergedOptions.qualityLoop) cliFlags.push("--quality-loop");
839→        if (mergedOptions.testgen) cliFlags.push("--testgen");
840→
841→        // Read token usage from SessionEnd hook files (AC-5, AC-6)
842→        const tokenUsage = getTokenUsageForRun(undefined, true); // cleanup after reading
843→
844→        // Record the run
845→        await metricsWriter.recordRun({
846→          issues: issueNumbers,
847→          phases: Array.from(allPhases),
848→          outcome: determineOutcome(passed, results.length),
849→          duration: totalDuration,
850→          model: process.env.ANTHROPIC_MODEL ?? "opus",
851→          flags: cliFlags,
852→          metrics: {
853→            tokensUsed: tokenUsage.tokensUsed,
854→            filesChanged: totalFilesChanged,
855→            linesAdded: totalLinesAdded,
856→            acceptanceCriteria: 0, // Would need to parse from issue
857→            qaIterations: totalQaIterations,
858→            // Token breakdown (AC-6)
859→            inputTokens: tokenUsage.inputTokens || undefined,
860→            outputTokens: tokenUsage.outputTokens || undefined,
861→            cacheTokens: tokenUsage.cacheTokens || undefined,
862→          },
863→        });
864→
865→        if (config.verbose) {
866→          console.log(
867→            chalk.gray(`  📊 Metrics recorded to .sequant/metrics.json`),
868→          );
869→        }
870→      } catch (metricsError) {
871→        // Metrics recording errors shouldn't stop execution
872→        if (config.verbose) {
873→          console.log(
874→            chalk.yellow(`  ⚠️  Metrics recording error: ${metricsError}`),
875→          );
876→        }
877→      }
878→    }
879→
880→    // Summary
881→    console.log("\n" + ui.divider());
882→    console.log(colors.info("  Summary"));
883→    console.log(ui.divider());
884→
885→    console.log(
886→      colors.muted(
887→        `\n  Results: ${colors.success(`${passed} passed`)}, ${colors.error(`${failed} failed`)}`,
888→      ),
889→    );
890→
891→    for (const result of results) {
892→      const status = result.success
893→        ? ui.statusIcon("success")
894→        : ui.statusIcon("error");
895→      const duration = result.durationSeconds
896→        ? colors.muted(` (${formatDuration(result.durationSeconds)})`)
897→        : "";
898→      const phases = result.phaseResults
899→        .map((p) =>
900→          p.success ? colors.success(p.phase) : colors.error(p.phase),
901→        )
902→        .join(" → ");
903→      const loopInfo = result.loopTriggered ? colors.warning(" [loop]") : "";
904→      const prInfo = result.prUrl
905→        ? colors.muted(` → PR #${result.prNumber}`)
906→        : "";
907→      console.log(
908→        `  ${status} #${result.issueNumber}: ${phases}${loopInfo}${prInfo}${duration}`,
909→      );
910→    }
911→
912→    console.log("");
913→
914→    if (logPath) {
915→      console.log(colors.muted(`  📝 Log: ${logPath}`));
916→      console.log("");
917→    }
918→
919→    // Suggest merge checks for multi-issue batches
920→    if (results.length > 1 && passed > 0 && !config.dryRun) {
921→      console.log(
922→        colors.muted("  💡 Verify batch integration before merging:"),
923→      );
924→      console.log(colors.muted("     sequant merge --check"));
925→      console.log("");
926→    }
927→
928→    if (config.dryRun) {
929→      console.log(
930→        colors.warning(
931→          "  ℹ️  This was a dry run. Use without --dry-run to execute.",
932→        ),
933→      );
934→      console.log("");
935→    }
936→
937→    // Set exit code if any failed
938→    if (failed > 0 && !config.dryRun) {
939→      exitCode = 1;
940→    }
941→  } finally {
942→    // Always dispose shutdown manager to clean up signal handlers
943→    shutdown.dispose();
944→  }
945→
946→  // Exit with error if any failed (outside try/finally so dispose() runs first)
947→  if (exitCode !== 0) {
948→    process.exit(exitCode);
949→  }
950→}
