 57→/**
 58→ * Parse QA verdict from phase output
 59→ *
 60→ * Looks for verdict patterns in the QA output:
 61→ * - "### Verdict: READY_FOR_MERGE"
 62→ * - "**Verdict:** AC_NOT_MET"
 63→ * - "Verdict: AC_MET_BUT_NOT_A_PLUS"
 64→ *
 65→ * @param output - The captured output from QA phase
 66→ * @returns The parsed verdict or null if not found
 67→ */
 68→export function parseQaVerdict(output: string): QaVerdict | null {
 69→  if (!output) return null;
 70→
 71→  // Match various verdict formats:
 72→  // - "### Verdict: X" (markdown header)
 73→  // - "**Verdict:** X" (bold label with colon inside)
 74→  // - "**Verdict:** **X**" (bold label and bold value)
 75→  // - "Verdict: X" (plain)
 76→  // Case insensitive, handles optional markdown formatting
 77→  const verdictMatch = output.match(
 78→    /(?:###?\s*)?(?:\*\*)?Verdict:?\*?\*?\s*\*?\*?\s*(READY_FOR_MERGE|AC_MET_BUT_NOT_A_PLUS|AC_NOT_MET|NEEDS_VERIFICATION)\*?\*?/i,
 79→  );
 80→
 81→  if (!verdictMatch) return null;
 82→
 83→  // Normalize to uppercase with underscores
 84→  const verdict = verdictMatch[1].toUpperCase().replace(/-/g, "_") as QaVerdict;
 85→  return verdict;
 86→}
 87→
 88→/**
 89→ * Format duration in human-readable format
 90→ */
 91→export function formatDuration(seconds: number): string {
 92→  if (seconds < 60) {
 93→    return `${seconds.toFixed(1)}s`;
 94→  }
 95→  const mins = Math.floor(seconds / 60);
 96→  const secs = seconds % 60;
 97→  return `${mins}m ${secs.toFixed(0)}s`;
 98→}
