100→/**
101→ * Get the prompt for a phase with the issue number substituted
102→ */
103→export function getPhasePrompt(phase: Phase, issueNumber: number): string {
104→  return PHASE_PROMPTS[phase].replace(/\{issue\}/g, String(issueNumber));
105→}
106→
107→/**
108→ * Execute a single phase for an issue using Claude Agent SDK
109→ */
110→export async function executePhase(
111→  issueNumber: number,
112→  phase: Phase,
113→  config: ExecutionConfig,
114→  sessionId?: string,
115→  worktreePath?: string,
116→  shutdownManager?: ShutdownManager,
117→  spinner?: PhaseSpinner,
118→): Promise<PhaseResult & { sessionId?: string }> {
119→  const startTime = Date.now();
120→
121→  if (config.dryRun) {
122→    // Dry run - just simulate
123→    if (config.verbose) {
124→      console.log(chalk.gray(`    Would execute: /${phase} ${issueNumber}`));
125→    }
126→    return {
127→      phase,
128→      success: true,
129→      durationSeconds: 0,
130→    };
131→  }
132→
133→  const prompt = getPhasePrompt(phase, issueNumber);
134→
135→  if (config.verbose) {
136→    console.log(chalk.gray(`    Prompt: ${prompt}`));
137→    if (worktreePath && ISOLATED_PHASES.includes(phase)) {
138→      console.log(chalk.gray(`    Worktree: ${worktreePath}`));
139→    }
140→  }
141→
142→  // Determine working directory and environment
143→  const shouldUseWorktree = worktreePath && ISOLATED_PHASES.includes(phase);
144→  const cwd = shouldUseWorktree ? worktreePath : process.cwd();
145→
146→  // Track stderr for error diagnostics (declared outside try for catch access)
147→  let capturedStderr = "";
148→
149→  try {
150→    // Check if shutdown is in progress
151→    if (shutdownManager?.shuttingDown) {
152→      return {
153→        phase,
154→        success: false,
155→        durationSeconds: 0,
156→        error: "Shutdown in progress",
157→      };
158→    }
159→
160→    // Create abort controller for timeout
161→    const abortController = new AbortController();
162→    const timeoutId = setTimeout(() => {
163→      abortController.abort();
164→    }, config.phaseTimeout * 1000);
165→
166→    // Register abort controller with shutdown manager for graceful shutdown
167→    if (shutdownManager) {
168→      shutdownManager.setAbortController(abortController);
169→    }
170→
171→    let resultSessionId: string | undefined;
172→    let resultMessage: SDKResultMessage | undefined;
173→    let lastError: string | undefined;
174→    let capturedOutput = "";
175→
176→    // Build environment with worktree isolation variables
177→    const env: Record<string, string> = {
178→      ...process.env,
179→      CLAUDE_HOOKS_SMART_TESTS: config.noSmartTests ? "false" : "true",
180→    };
181→
182→    // Set worktree isolation environment variables
183→    if (shouldUseWorktree) {
184→      env.SEQUANT_WORKTREE = worktreePath;
185→      env.SEQUANT_ISSUE = String(issueNumber);
186→    }
187→
188→    // Set orchestration context for skills to detect they're part of a workflow
189→    // Skills can check these to skip redundant pre-flight checks
190→    env.SEQUANT_ORCHESTRATOR = "sequant-run";
191→    env.SEQUANT_PHASE = phase;
192→
193→    // Execute using Claude Agent SDK
194→    // Note: Don't resume sessions when switching to worktree (different cwd breaks resume)
195→    const canResume = sessionId && !shouldUseWorktree;
196→
197→    // Get MCP servers config if enabled
198→    // Reads from Claude Desktop config and passes to SDK for headless MCP support
199→    const mcpServers = config.mcp ? getMcpServersConfig() : undefined;
200→
201→    // Track whether we're actively streaming verbose output
202→    // Pausing spinner once per streaming session prevents truncation from rapid pause/resume cycles
203→    // (Issue #283: ora's stop() clears the current line, which can truncate output when
204→    // pause/resume is called for every chunk in rapid succession)
205→    let verboseStreamingActive = false;
206→
207→    const queryInstance = query({
208→      prompt,
209→      options: {
210→        abortController,
211→        cwd,
212→        // Load project settings including skills
213→        settingSources: ["project"],
214→        // Use Claude Code's system prompt and tools
215→        systemPrompt: { type: "preset", preset: "claude_code" },
216→        tools: { type: "preset", preset: "claude_code" },
217→        // Bypass permissions for headless execution
218→        permissionMode: "bypassPermissions",
219→        allowDangerouslySkipPermissions: true,
220→        // Resume from previous session if provided (but not when switching directories)
221→        ...(canResume ? { resume: sessionId } : {}),
222→        // Configure smart tests and worktree isolation via environment
223→        env,
224→        // Pass MCP servers for headless mode (AC-2)
225→        ...(mcpServers ? { mcpServers } : {}),
226→        // Capture stderr for debugging (helps diagnose early exit failures)
227→        stderr: (data: string) => {
228→          capturedStderr += data;
229→          // Write stderr in verbose mode
230→          if (config.verbose) {
231→            // Pause spinner once to avoid truncation (Issue #283)
232→            if (!verboseStreamingActive) {
233→              spinner?.pause();
234→              verboseStreamingActive = true;
235→            }
236→            process.stderr.write(chalk.red(data));
237→          }
238→        },
239→      },
240→    });
241→
242→    // Stream and process messages
243→    for await (const message of queryInstance) {
244→      // Capture session ID from system init message
245→      if (message.type === "system" && message.subtype === "init") {
246→        resultSessionId = message.session_id;
247→      }
248→
249→      // Capture output from assistant messages
250→      if (message.type === "assistant") {
251→        // Extract text content from the message
252→        const content = message.message.content as Array<{
253→          type: string;
254→          text?: string;
255→        }>;
256→        const textContent = content
257→          .filter((c) => c.type === "text" && c.text)
258→          .map((c) => c.text)
259→          .join("");
260→        if (textContent) {
261→          capturedOutput += textContent;
262→          // Show streaming output in verbose mode
263→          if (config.verbose) {
264→            // Pause spinner once at start of streaming to avoid truncation
265→            // (Issue #283: repeated pause/resume causes ora to clear lines between chunks)
266→            if (!verboseStreamingActive) {
267→              spinner?.pause();
268→              verboseStreamingActive = true;
269→            }
270→            process.stdout.write(chalk.gray(textContent));
271→          }
272→        }
273→      }
274→
275→      // Capture the final result
276→      if (message.type === "result") {
277→        resultMessage = message;
278→      }
279→    }
280→
281→    // Resume spinner after streaming completes (if we paused it)
282→    if (verboseStreamingActive) {
283→      spinner?.resume();
284→      verboseStreamingActive = false;
285→    }
286→
287→    clearTimeout(timeoutId);
288→
289→    // Clear abort controller from shutdown manager
290→    if (shutdownManager) {
291→      shutdownManager.clearAbortController();
292→    }
293→
294→    const durationSeconds = (Date.now() - startTime) / 1000;
295→
296→    // Check result status
297→    if (resultMessage) {
298→      if (resultMessage.subtype === "success") {
299→        // For QA phase, check the verdict to determine actual success
300→        // SDK "success" just means the query completed - we need to parse the verdict
301→        if (phase === "qa" && capturedOutput) {
302→          const verdict = parseQaVerdict(capturedOutput);
303→          // Only READY_FOR_MERGE and NEEDS_VERIFICATION are considered passing
304→          // NEEDS_VERIFICATION is external verification, not a code quality issue
305→          if (
306→            verdict &&
307→            verdict !== "READY_FOR_MERGE" &&
308→            verdict !== "NEEDS_VERIFICATION"
309→          ) {
310→            return {
311→              phase,
312→              success: false,
313→              durationSeconds,
314→              error: `QA verdict: ${verdict}`,
315→              sessionId: resultSessionId,
316→              output: capturedOutput,
317→              verdict, // Include parsed verdict
318→            };
319→          }
320→          // Pass case - include verdict for logging
321→          return {
322→            phase,
323→            success: true,
324→            durationSeconds,
325→            sessionId: resultSessionId,
326→            output: capturedOutput,
327→            verdict: verdict ?? undefined, // Include if found
328→          };
329→        }
330→
331→        return {
332→          phase,
333→          success: true,
334→          durationSeconds,
335→          sessionId: resultSessionId,
336→          output: capturedOutput,
337→        };
338→      } else {
339→        // Handle error subtypes
340→        const errorSubtype = resultMessage.subtype;
341→        if (errorSubtype === "error_max_turns") {
342→          lastError = "Max turns reached";
343→        } else if (errorSubtype === "error_during_execution") {
344→          lastError =
345→            resultMessage.errors?.join(", ") || "Error during execution";
346→        } else if (errorSubtype === "error_max_budget_usd") {
347→          lastError = "Budget limit exceeded";
348→        } else {
349→          lastError = `Error: ${errorSubtype}`;
350→        }
351→
352→        return {
353→          phase,
354→          success: false,
355→          durationSeconds,
356→          error: lastError,
357→          sessionId: resultSessionId,
358→        };
359→      }
360→    }
361→
362→    // No result message received
363→    return {
364→      phase,
365→      success: false,
366→      durationSeconds: (Date.now() - startTime) / 1000,
367→      error: "No result received from Claude",
368→      sessionId: resultSessionId,
369→    };
370→  } catch (err) {
371→    const durationSeconds = (Date.now() - startTime) / 1000;
372→    const error = err instanceof Error ? err.message : String(err);
373→
374→    // Check if it was an abort (timeout)
375→    if (error.includes("abort") || error.includes("AbortError")) {
376→      return {
377→        phase,
378→        success: false,
379→        durationSeconds,
380→        error: `Timeout after ${config.phaseTimeout}s`,
381→      };
382→    }
383→
384→    // Include stderr in error message if available (helps diagnose early exit failures)
385→    const stderrSuffix = capturedStderr
386→      ? `\nStderr: ${capturedStderr.slice(0, 500)}`
387→      : "";
388→
389→    return {
390→      phase,
391→      success: false,
392→      durationSeconds,
393→      error: error + stderrSuffix,
394→    };
395→  }
396→}
397→
398→/**
399→ * Execute a phase with automatic retry for cold-start failures and MCP fallback.
400→ *
401→ * Retry strategy:
402→ * 1. If phase fails within COLD_START_THRESHOLD_SECONDS, retry up to COLD_START_MAX_RETRIES times
403→ * 2. If still failing and MCP is enabled, retry once with MCP disabled (npx-based MCP servers
404→ *    can fail on first run due to cold-cache issues)
405→ *
406→ * The MCP fallback is safe because MCP servers are optional enhancements, not required
407→ * for core functionality.
408→ */
409→/**
410→ * @internal Exported for testing only
411→ */
412→export async function executePhaseWithRetry(
413→  issueNumber: number,
414→  phase: Phase,
415→  config: ExecutionConfig,
416→  sessionId?: string,
417→  worktreePath?: string,
418→  shutdownManager?: ShutdownManager,
419→  spinner?: PhaseSpinner,
420→  /** @internal Injected for testing — defaults to module-level executePhase */
421→  executePhaseFn: typeof executePhase = executePhase,
422→): Promise<PhaseResult & { sessionId?: string }> {
423→  // Skip retry logic if explicitly disabled
424→  if (config.retry === false) {
425→    return executePhaseFn(
426→      issueNumber,
427→      phase,
428→      config,
429→      sessionId,
430→      worktreePath,
431→      shutdownManager,
432→      spinner,
433→    );
434→  }
435→
436→  let lastResult: PhaseResult & { sessionId?: string };
437→
438→  // Phase 1: Cold-start retry attempts (with MCP enabled if configured)
439→  for (let attempt = 0; attempt <= COLD_START_MAX_RETRIES; attempt++) {
440→    lastResult = await executePhaseFn(
441→      issueNumber,
442→      phase,
443→      config,
444→      sessionId,
445→      worktreePath,
446→      shutdownManager,
447→      spinner,
448→    );
449→
450→    const duration = lastResult.durationSeconds ?? 0;
451→
452→    // Success or genuine failure (took long enough to be real work)
453→    if (lastResult.success || duration >= COLD_START_THRESHOLD_SECONDS) {
454→      return lastResult;
455→    }
456→
457→    // Cold-start failure detected — retry
458→    if (attempt < COLD_START_MAX_RETRIES) {
459→      if (config.verbose) {
460→        console.log(
461→          chalk.yellow(
462→            `\n    ⟳ Cold-start failure detected (${duration.toFixed(1)}s), retrying... (attempt ${attempt + 2}/${COLD_START_MAX_RETRIES + 1})`,
463→          ),
464→        );
465→      }
466→    }
467→  }
468→
469→  // Capture the original error for better diagnostics
470→  const originalError = lastResult!.error;
471→
472→  // Phase 2: MCP fallback - if MCP is enabled and we're still failing, try without MCP
473→  // This handles npx-based MCP servers that fail on first run due to cold-cache issues
474→  if (config.mcp && !lastResult!.success) {
475→    console.log(
476→      chalk.yellow(
477→        `\n    ⚠️ Phase failed with MCP enabled, retrying without MCP...`,
478→      ),
479→    );
480→
481→    // Create config copy with MCP disabled
482→    const configWithoutMcp: ExecutionConfig = {
483→      ...config,
484→      mcp: false,
485→    };
486→
487→    const retryResult = await executePhaseFn(
488→      issueNumber,
489→      phase,
490→      configWithoutMcp,
491→      sessionId,
492→      worktreePath,
493→      shutdownManager,
494→      spinner,
495→    );
496→
497→    if (retryResult.success) {
498→      console.log(
499→        chalk.green(
500→          `    ✓ Phase succeeded without MCP (MCP cold-start issue detected)`,
501→        ),
502→      );
503→      return retryResult;
504→    }
505→
506→    // Both attempts failed - return original error for better diagnostics
507→    return {
508→      ...lastResult!,
509→      error: originalError,
510→    };
511→  }
512→
513→  return lastResult!;
514→}
515→

