  1→/**
  2→ * Phase Mapping Module
  3→ *
  4→ * Maps issue labels to workflow phases and parses recommended workflows:
  5→ * - Label-based phase detection
  6→ * - Recommended workflow parsing from spec output
  7→ * - UI/bug/docs/complex label recognition
  8→ *
  9→ * @module phase-mapper
 10→ */
 11→
 12→import { spawnSync } from "child_process";
 13→import type { Phase } from "./types.js";
 14→import { getResumablePhasesForIssue } from "./phase-detection.js";
 15→
 16→/**
 17→ * UI-related labels that trigger automatic test phase
 18→ */
 19→export const UI_LABELS = ["ui", "frontend", "admin", "web", "browser"];
 20→
 21→/**
 22→ * Bug-related labels that skip spec phase
 23→ */
 24→export const BUG_LABELS = ["bug", "fix", "hotfix", "patch"];
 25→
 26→/**
 27→ * Documentation labels that skip spec phase
 28→ */
 29→export const DOCS_LABELS = ["docs", "documentation", "readme"];
 30→
 31→/**
 32→ * Complex labels that enable quality loop
 33→ */
 34→export const COMPLEX_LABELS = ["complex", "refactor", "breaking", "major"];
 35→
 36→/**
 37→ * Security-related labels that trigger security-review phase
 38→ */
 39→export const SECURITY_LABELS = [
 40→  "security",
 41→  "auth",
 42→  "authentication",
 43→  "permissions",
 44→  "admin",
 45→];
 46→
 47→/**
 48→ * Options that affect phase determination
 49→ */
 50→interface PhaseOptions {
 51→  testgen?: boolean;
 52→}
 53→
 54→/**
 55→ * Detect phases based on issue labels (like /solve logic)
 56→ */
 57→export function detectPhasesFromLabels(labels: string[]): {
 58→  phases: Phase[];
 59→  qualityLoop: boolean;
 60→} {
 61→  const lowerLabels = labels.map((l) => l.toLowerCase());
 62→
 63→  // Check for bug/fix labels → exec → qa (skip spec)
 64→  const isBugFix = lowerLabels.some((label) =>
 65→    BUG_LABELS.some((bugLabel) => label.includes(bugLabel)),
 66→  );
 67→
 68→  // Check for docs labels → exec → qa (skip spec)
 69→  const isDocs = lowerLabels.some((label) =>
 70→    DOCS_LABELS.some((docsLabel) => label.includes(docsLabel)),
 71→  );
 72→
 73→  // Check for UI labels → add test phase
 74→  const isUI = lowerLabels.some((label) =>
 75→    UI_LABELS.some((uiLabel) => label.includes(uiLabel)),
 76→  );
 77→
 78→  // Check for complex labels → enable quality loop
 79→  const isComplex = lowerLabels.some((label) =>
 80→    COMPLEX_LABELS.some((complexLabel) => label.includes(complexLabel)),
 81→  );
 82→
 83→  // Check for security labels → add security-review phase
 84→  const isSecurity = lowerLabels.some((label) =>
 85→    SECURITY_LABELS.some((secLabel) => label.includes(secLabel)),
 86→  );
 87→
 88→  // Build phase list
 89→  let phases: Phase[];
 90→
 91→  if (isBugFix || isDocs) {
 92→    // Simple workflow: exec → qa
 93→    phases = ["exec", "qa"];
 94→  } else if (isUI) {
 95→    // UI workflow: spec → exec → test → qa
 96→    phases = ["spec", "exec", "test", "qa"];
 97→  } else {
 98→    // Standard workflow: spec → exec → qa
 99→    phases = ["spec", "exec", "qa"];
100→  }
101→
102→  // Add security-review phase after spec if security labels detected
103→  if (isSecurity && phases.includes("spec")) {
104→    const specIndex = phases.indexOf("spec");
105→    phases.splice(specIndex + 1, 0, "security-review");
106→  }
107→
108→  return { phases, qualityLoop: isComplex };
109→}
110→
111→/**
112→ * Parse recommended workflow from /spec output
113→ *
114→ * Looks for:
115→ * ## Recommended Workflow
116→ * **Phases:** exec → qa
117→ * **Quality Loop:** enabled|disabled
118→ */
119→export function parseRecommendedWorkflow(output: string): {
120→  phases: Phase[];
121→  qualityLoop: boolean;
122→} | null {
123→  // Find the Recommended Workflow section
124→  const workflowMatch = output.match(
125→    /## Recommended Workflow[\s\S]*?\*\*Phases:\*\*\s*([^\n]+)/i,
126→  );
127→
128→  if (!workflowMatch) {
129→    return null;
130→  }
131→
132→  // Parse phases from "exec → qa" or "spec → exec → test → qa" format
133→  const phasesStr = workflowMatch[1].trim();
134→  const phaseNames = phasesStr
135→    .split(/\s*→\s*|\s*->\s*|\s*,\s*/)
136→    .map((p) => p.trim().toLowerCase())
137→    .filter((p) => p.length > 0);
138→
139→  // Validate and convert to Phase type
140→  const validPhases: Phase[] = [];
141→  for (const name of phaseNames) {
142→    if (
143→      [
144→        "spec",
145→        "security-review",
146→        "testgen",
147→        "exec",
148→        "test",
149→        "qa",
150→        "loop",
151→      ].includes(name)
152→    ) {
153→      validPhases.push(name as Phase);
154→    }
155→  }
156→
157→  if (validPhases.length === 0) {
158→    return null;
159→  }
160→
161→  // Parse quality loop setting
162→  const qualityLoopMatch = output.match(
163→    /\*\*Quality Loop:\*\*\s*(enabled|disabled|true|false|yes|no)/i,
164→  );
165→  const qualityLoop = qualityLoopMatch
166→    ? ["enabled", "true", "yes"].includes(qualityLoopMatch[1].toLowerCase())
167→    : false;
168→
169→  return { phases: validPhases, qualityLoop };
170→}
171→
172→/**
173→ * Check if an issue has UI-related labels
174→ */
175→export function hasUILabels(labels: string[]): boolean {
176→  return labels.some((label) =>
177→    UI_LABELS.some((uiLabel) => label.toLowerCase().includes(uiLabel)),
178→  );
179→}
180→
181→/**
182→ * Determine phases to run based on options and issue labels
183→ */
184→export function determinePhasesForIssue(
185→  basePhases: Phase[],
186→  labels: string[],
187→  options: PhaseOptions,
188→): Phase[] {
189→  const phases = [...basePhases];
190→
191→  // Add testgen phase after spec if requested
192→  if (options.testgen && phases.includes("spec")) {
193→    const specIndex = phases.indexOf("spec");
194→    if (!phases.includes("testgen")) {
195→      phases.splice(specIndex + 1, 0, "testgen");
196→    }
197→  }
198→
199→  // Auto-detect UI issues and add test phase
200→  if (hasUILabels(labels) && !phases.includes("test")) {
201→    // Add test phase before qa if present, otherwise at the end
202→    const qaIndex = phases.indexOf("qa");
203→    if (qaIndex !== -1) {
204→      phases.splice(qaIndex, 0, "test");
205→    } else {
206→      phases.push("test");
207→    }
208→  }
209→
210→  return phases;
211→}
212→
213→/**
214→ * Filter phases based on resume status.
215→ *
216→ * When `resume` is true, calls `getResumablePhasesForIssue` to determine
217→ * which phases have already completed (via GitHub issue comment markers)
218→ * and removes them from the execution list.
219→ *
220→ * @param issueNumber - GitHub issue number
221→ * @param phases - The phases to potentially filter
222→ * @param resume - Whether the --resume flag is set
223→ * @returns Object with filtered phases and any skipped phases
224→ */
225→export function filterResumedPhases(
226→  issueNumber: number,
227→  phases: Phase[],
228→  resume: boolean,
229→): { phases: Phase[]; skipped: Phase[] } {
230→  if (!resume) {
231→    return { phases: [...phases], skipped: [] };
232→  }
233→
234→  const resumable = getResumablePhasesForIssue(issueNumber, phases) as Phase[];
235→  const skipped = phases.filter((p) => !resumable.includes(p));
236→  return { phases: resumable, skipped };
237→}
238→
239→/**
240→ * Fetch issue info from GitHub
241→ */
242→export async function getIssueInfo(
243→  issueNumber: number,
244→): Promise<{ title: string; labels: string[] }> {
245→  try {
246→    const result = spawnSync(
247→      "gh",
248→      ["issue", "view", String(issueNumber), "--json", "title,labels"],
249→      { stdio: "pipe" },
250→    );
251→
252→    if (result.status === 0) {
253→      const data = JSON.parse(result.stdout.toString());
254→      return {
255→        title: data.title || `Issue #${issueNumber}`,
256→        labels: Array.isArray(data.labels)
257→          ? data.labels.map((l: { name: string }) => l.name)
258→          : [],
259→      };
260→    }
261→  } catch {
262→    // Ignore errors, use defaults
263→  }
264→
265→  return { title: `Issue #${issueNumber}`, labels: [] };
266→}
267→
268→/**
269→ * Parse dependencies from issue body and labels
270→ * Returns array of issue numbers this issue depends on
271→ */
272→export function parseDependencies(issueNumber: number): number[] {
273→  try {
274→    const result = spawnSync(
275→      "gh",
276→      ["issue", "view", String(issueNumber), "--json", "body,labels"],
277→      { stdio: "pipe" },
278→    );
279→
280→    if (result.status !== 0) return [];
281→
282→    const data = JSON.parse(result.stdout.toString());
283→    const dependencies: number[] = [];
284→
285→    // Parse from body: "Depends on: #123" or "**Depends on**: #123"
286→    if (data.body) {
287→      const bodyMatch = data.body.match(
288→        /\*?\*?depends\s+on\*?\*?:?\s*#?(\d+)/gi,
289→      );
290→      if (bodyMatch) {
291→        for (const match of bodyMatch) {
292→          const numMatch = match.match(/(\d+)/);
293→          if (numMatch) {
294→            dependencies.push(parseInt(numMatch[1], 10));
295→          }
296→        }
297→      }
298→    }
299→
300→    // Parse from labels: "depends-on/123" or "depends-on-123"
301→    if (data.labels && Array.isArray(data.labels)) {
302→      for (const label of data.labels) {
303→        const labelName = label.name || label;
304→        const labelMatch = labelName.match(/depends-on[-/](\d+)/i);
305→        if (labelMatch) {
306→          dependencies.push(parseInt(labelMatch[1], 10));
307→        }
308→      }
309→    }
310→
311→    return [...new Set(dependencies)]; // Remove duplicates
312→  } catch {
313→    return [];
314→  }
315→}
316→
317→/**
318→ * Sort issues by dependencies (topological sort)
319→ * Issues with no dependencies come first, then issues that depend on them
320→ */
321→export function sortByDependencies(issueNumbers: number[]): number[] {
322→  // Build dependency graph
323→  const dependsOn = new Map<number, number[]>();
324→  for (const issue of issueNumbers) {
325→    const deps = parseDependencies(issue);
326→    // Only include dependencies that are in our issue list
327→    dependsOn.set(
328→      issue,
329→      deps.filter((d) => issueNumbers.includes(d)),
330→    );
331→  }
332→
333→  // Topological sort using Kahn's algorithm
334→  const inDegree = new Map<number, number>();
335→  for (const issue of issueNumbers) {
336→    inDegree.set(issue, 0);
337→  }
338→  for (const deps of dependsOn.values()) {
339→    for (const dep of deps) {
340→      inDegree.set(dep, (inDegree.get(dep) || 0) + 1);
341→    }
342→  }
343→
344→  // Note: inDegree counts how many issues depend on each issue
345→  // We want to process issues that nothing depends on last
346→  // So we sort by: issues nothing depends on first, then dependent issues
347→  const sorted: number[] = [];
348→  const queue: number[] = [];
349→
350→  // Start with issues that have no dependencies
